import { test, expect, Page } from '@playwright/test';

/**
 * Visual Regression Testing Specification
 */

const VRT_DATE = '2026-01-25';

async function injectVRTData(page: Page) {
    const dateStr = VRT_DATE;
    // 1. Pipe all console logs
    page.on('console', msg => console.log(`BROWSER LOG [${msg.type()}]: ${msg.text()}`));

    // 2. Inject specific VRT data using the built-in E2E override hook
    // We use addInitScript to ensure this is set BEFORE the app initializes.
    await page.addInitScript(({ dateStr }) => {
        const records = {
            [dateStr]: {
                date: dateStr,
                beds: {},
                lastUpdated: new Date().toISOString(),
                schemaVersion: 1,
                nursesDayShift: ["Enfermero VRT 1", "Enfermero VRT 2"],
                tensDayShift: ["TENS VRT 1", "TENS VRT 2", "TENS VRT 3"],
                activeExtraBeds: []
            }
        };

        // Initialize all 18 beds with dummy patient data
        // Explicitly naming the beds to match BEDS constant in the app
        const bedIds = [
            'R1', 'R2', 'R3', 'R4',
            'NEO1', 'NEO2',
            'H1C1', 'H1C2', 'H2C1', 'H2C2', 'H3C1', 'H3C2',
            'H4C1', 'H4C2', 'H5C1', 'H5C2', 'H6C1', 'H6C2'
        ];

        bedIds.forEach((bedId, i) => {
            (records[dateStr].beds as any)[bedId] = {
                id: bedId,
                bedId: bedId, // Some components might use bedId
                patientName: `Paciente VRT ${i + 1}`,
                rut: `12.345.678-${i + 1}`,
                age: "45",
                diagnosis: `Diagnóstico VRT para cama ${bedId}`,
                isOccupied: true,
                admissionDate: dateStr,
                daysHospitalized: i + 1,
                insurance: 'FONASA A',
                biologicalSex: i % 2 === 0 ? 'Femenino' : 'Masculino',
                bedMode: 'Adulto',
                status: 'Estable'
            };
        });

        // Set the override globally
        (window as any).__HHR_E2E_OVERRIDE__ = records;

        // Also inject mock user data for login
        const mockUser = {
            uid: 'e2e-test-editor-uid',
            email: 'hospitalizados@hospitalhangaroa.cl',
            role: 'nurse_hospital'
        };
        const mockPassport = {
            email: 'hospitalizados@hospitalhangaroa.cl',
            role: 'nurse_hospital',
            timestamp: Date.now()
        };

        localStorage.setItem('hhr_offline_user', JSON.stringify(mockUser));
        localStorage.setItem('hhr_offline_passport', JSON.stringify(mockPassport));

        console.warn(`[E2E] addInitScript injected override for ${dateStr}`);
    }, { dateStr });

    // 3. Navigate
    await page.goto(`/censo?date=${VRT_DATE}`);
    await page.waitForLoadState('domcontentloaded');
}

test.describe('Visual Regression Testing', () => {

    test('Login View baseline', async ({ page }) => {
        await page.goto('/');
        await expect(page.getByText('Hospital Hanga Roa')).toBeVisible({ timeout: 10000 });
        await page.waitForLoadState('networkidle');
        await expect(page).toHaveScreenshot('login-view.png', {
            maxDiffPixelRatio: 0.01,
            animations: 'disabled'
        });
    });

    test('Census Dashboard baseline', async ({ page }) => {
        await injectVRTData(page);

        // Wait for table to be ready
        const table = page.getByTestId('census-table');
        await expect(table).toBeVisible({ timeout: 15000 });
        await page.waitForTimeout(2000); // Wait for React render

        // Mask dynamic data
        await expect(page).toHaveScreenshot('census-dashboard.png', {
            maxDiffPixelRatio: 0.02,
            animations: 'disabled',
            mask: [
                page.locator('.text-slate-400').filter({ hasText: /:/ }), // Potential clocks
                page.locator('nav').first(),
            ]
        });
    });

    test('3D Hospital Map baseline', async ({ page }) => {
        await injectVRTData(page);
        await page.goto(`/censo?date=${VRT_DATE}`);

        // Find the map toggle button by title
        const mapButton = page.locator('button[title="Ver Mapa 3D"]');
        await expect(mapButton).toBeVisible({ timeout: 10000 });
        await mapButton.click();

        // Wait for 3D loader to disappear
        const loader = page.locator('text=Cargando entorno 3D');
        await expect(loader).not.toBeVisible({ timeout: 30000 });

        const canvas = page.locator('canvas');
        await expect(canvas).toBeVisible({ timeout: 10000 });

        // Extra time for Three.js textures and lighting to settle
        await page.waitForTimeout(5000);

        await expect(page).toHaveScreenshot('hospital-3d-map.png', {
            maxDiffPixelRatio: 0.1,
            mask: [page.locator('.lucide-search'), page.locator('.lucide-box')] // Mask transient UI
        });
    });

    test('Patient Dialog UI baseline', async ({ page }) => {
        await injectVRTData(page);
        await page.goto(`/censo?date=${VRT_DATE}`);

        // Wait for table to be ready
        const table = page.getByTestId('census-table');
        await expect(table).toBeVisible({ timeout: 15000 });

        // Wait for data to load in the table - Use bed ID 'R1' which is stable text
        const patientRow = page.locator('tr').filter({ hasText: 'R1' });
        await expect(patientRow).toBeVisible({ timeout: 15000 });

        // Clicking the age field opens the Demographics Modal
        const ageField = patientRow.locator('input[placeholder="Edad"]');
        await ageField.click();

        const dialog = page.locator('role=dialog');
        await expect(dialog).toBeVisible({ timeout: 10000 });

        // Give time for animations
        await page.waitForTimeout(1000);

        await expect(dialog).toHaveScreenshot('patient-demographics-dialog.png', {
            maxDiffPixelRatio: 0.05
        });
    });
});

import { CENSUS_DEFAULT_RECIPIENTS } from '../../constants/email';
import { buildCensusMasterBuffer, getCensusMasterFilename } from '../../services/exporters/censusMasterWorkbook';
import { validateExcelBuffer, validateExcelFilename, MIN_EXCEL_SIZE } from '../../services/exporters/excelValidation';
import { sendCensusEmail } from '../../services/email/gmailClient';
import type { DailyRecord } from '../../types';

const ALLOWED_ROLES = ['nurse_hospital', 'admin'];

interface NetlifyEvent {
    httpMethod: string;
    headers: Record<string, string | undefined>;
    body: string | null;
    [key: string]: unknown;
}

export const handler = async (event: NetlifyEvent) => {
    if (event.httpMethod !== 'POST') {
        return {
            statusCode: 405,
            body: 'Método no permitido'
        };
    }

    const requesterRole = (event.headers['x-user-role'] || event.headers['X-User-Role']) as string | undefined;
    if (!requesterRole || !ALLOWED_ROLES.includes(requesterRole)) {
        return {
            statusCode: 403,
            body: 'No autorizado para enviar correos de censo.'
        };
    }

    if (!event.body) {
        return {
            statusCode: 400,
            body: 'Solicitud inválida: falta el cuerpo.'
        };
    }

    try {
        const payload = JSON.parse(event.body);
        const { date, records, recipients, nursesSignature, body, shareLink } = payload as {
            date: string;
            records: DailyRecord[];
            recipients?: string[];
            nursesSignature?: string;
            body?: string;
            shareLink?: string;
        };

        if (!date || !Array.isArray(records) || records.length === 0) {
            return {
                statusCode: 400,
                body: 'Solicitud inválida: falta la fecha o los datos del censo.'
            };
        }

        const monthRecords = records
            .filter((r): r is DailyRecord => Boolean(r?.date))
            .sort((a, b) => a.date.localeCompare(b.date));

        if (monthRecords.length === 0) {
            return {
                statusCode: 400,
                body: 'No hay registros disponibles para generar el Excel maestro.'
            };
        }

        const attachmentBufferRaw = await buildCensusMasterBuffer(monthRecords);
        const attachmentName = getCensusMasterFilename(date);

        // Validate buffer before proceeding
        const bufferValidation = validateExcelBuffer(attachmentBufferRaw);
        if (!bufferValidation.valid) {
            console.error('[CensusEmail] Buffer validation failed:', bufferValidation.error);
            return {
                statusCode: 500,
                body: `Error: El archivo Excel generado es inválido. ${bufferValidation.error} No se enviará el correo.`
            };
        }

        // Validate filename
        const filenameValidation = validateExcelFilename(attachmentName);
        if (!filenameValidation.valid) {
            console.error('[CensusEmail] Filename validation failed:', filenameValidation.error);
            return {
                statusCode: 500,
                body: `Error: El nombre del archivo es inválido. ${filenameValidation.error}`
            };
        }

        // Generate deterministic password based on census date
        const { generateCensusPassword } = await import('../../services/security/passwordGenerator');
        const password = shareLink ? '' : generateCensusPassword(date);

        // Ensure the PIN or Link is included in the email body
        let finalBody = body || '';

        if (shareLink) {
            const linkText = `Link de Acceso Seguro: ${shareLink}`;
            const instructions = `Este link le permitirá visualizar el censo de este mes y el anterior directamente en la plataforma.`;
            const shareBlock = `${linkText}\n${instructions}`;

            if (finalBody.includes('Saludos cordiales,')) {
                finalBody = finalBody.replace('Saludos cordiales,', `${shareBlock}\n\nSaludos cordiales,`);
            } else if (finalBody.includes('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')) {
                finalBody = finalBody.replace('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━', `${shareBlock}\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`);
            } else {
                finalBody = finalBody ? `${finalBody}\n\n${shareBlock}` : shareBlock;
            }
        } else if (password && !finalBody.includes(password)) {
            const pinLine = `Clave Excel: ${password}`;
            // ... (keep existing logic for PIN insertion)
            if (finalBody.includes('Saludos cordiales,')) {
                finalBody = finalBody.replace('Saludos cordiales,', `${pinLine}\n\nSaludos cordiales,`);
            } else if (finalBody.includes('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')) {
                finalBody = finalBody.replace('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━', `${pinLine}\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`);
            } else {
                finalBody = finalBody ? `${finalBody}\n\n${pinLine}` : pinLine;
            }
        }

        let attachmentBuffer = null;
        if (!shareLink) {

            const XlsxPopulate = require('xlsx-populate');
            attachmentBuffer = await XlsxPopulate.fromDataAsync(attachmentBufferRaw)
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                .then((workbook: any) => workbook.outputAsync({ password }));

            // Validate encrypted buffer
            if (!attachmentBuffer || attachmentBuffer.length < MIN_EXCEL_SIZE) {
                console.error('[CensusEmail] Encrypted buffer validation failed: buffer is too small or empty');
                return {
                    statusCode: 500,
                    body: 'Error: El archivo Excel encriptado es inválido o está vacío. No se enviará el correo.'
                };
            }
        }

        // Validate encrypted buffer
        if (!attachmentBuffer || attachmentBuffer.length < MIN_EXCEL_SIZE) {
            console.error('[CensusEmail] Encrypted buffer validation failed: buffer is too small or empty');
            return {
                statusCode: 500,
                body: 'Error: El archivo Excel encriptado es inválido o está vacío. No se enviará el correo.'
            };
        }

        const resolvedRecipients: string[] = Array.isArray(recipients) && recipients.length > 0
            ? recipients
            : CENSUS_DEFAULT_RECIPIENTS;

        const gmailResponse = await sendCensusEmail({
            date,
            recipients: resolvedRecipients,
            attachmentBuffer: attachmentBuffer || undefined,
            attachmentName: shareLink ? undefined : attachmentName,
            nursesSignature,
            body: finalBody,
            encryptionPin: password || undefined
        });

        // eslint-disable-next-line no-console
        console.log('Gmail send response', gmailResponse);

        return {
            statusCode: 200,
            body: JSON.stringify({
                success: true,
                message: 'Correo enviado correctamente.',
                gmailId: gmailResponse.id,
                censusDate: date,
                exportPassword: password
            })
        };
    } catch (error: unknown) {
        console.error('Error enviando correo de censo', error);
        const message = error instanceof Error ? error.message : 'Error desconocido enviando el correo.';
        return {
            statusCode: 500,
            body: message
        };
    }
};

import { handler as sendCensusEmailHandler } from '../netlify/functions/send-census-email';
import { generateDemoRecord, formatDateDDMMYYYY } from '../services';
import { getTodayISO } from '../utils/dateUtils';

const run = async () => {
    const today = getTodayISO();
    const demoRecord = generateDemoRecord(today);
    const records = [demoRecord];

    const event = {
        httpMethod: 'POST',
        headers: {
            'x-user-role': 'nurse_hospital',
            'x-user-email': 'local-test@example.com'
        },
        body: JSON.stringify({
            date: today,
            records,
            recipients: process.env.TEST_CENSUS_EMAIL ? [process.env.TEST_CENSUS_EMAIL] : undefined,
            nursesSignature: `Script local - ${formatDateDDMMYYYY(today)}`
        })
    } as any;

    const response = await sendCensusEmailHandler(event);
    console.log('Respuesta de prueba:', response);
};

run().catch(err => {
    console.error('Error ejecutando prueba local de envío de correo', err);
    process.exit(1);
});

/**
 * VirtualizedTable Component
 * Renders only visible rows for better performance with large datasets.
 * Uses @tanstack/react-virtual for virtualization.
 */

import React, { useRef } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';

interface VirtualizedTableProps<T> {
    /** Data items to render */
    items: T[];
    /** Height of each row in pixels */
    rowHeight: number;
    /** Maximum height of the table container */
    maxHeight: number;
    /** Render function for table header */
    renderHeader: () => React.ReactNode;
    /** Render function for each row */
    renderRow: (item: T, index: number) => React.ReactNode;
    /** Optional class name for the container */
    className?: string;
    /** Overscan - number of items to render above/below visible area */
    overscan?: number;
}

export function VirtualizedTable<T>({
    items,
    rowHeight,
    maxHeight,
    renderHeader,
    renderRow,
    className = '',
    overscan = 5
}: VirtualizedTableProps<T>) {
    const parentRef = useRef<HTMLDivElement>(null);

    const virtualizer = useVirtualizer({
        count: items.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => rowHeight,
        overscan
    });

    const virtualItems = virtualizer.getVirtualItems();
    const totalSize = virtualizer.getTotalSize();

    return (
        <div className={`bg-white rounded-xl shadow-sm border border-slate-200 ${className}`}>
            <div
                ref={parentRef}
                className="overflow-auto scrollbar-thin scrollbar-thumb-slate-300 scrollbar-track-transparent"
                style={{ maxHeight }}
            >
                <table className="w-full text-left border-collapse relative">
                    <thead>
                        {renderHeader()}
                    </thead>
                    <tbody
                        style={{
                            height: `${totalSize}px`,
                            width: '100%',
                            position: 'relative'
                        }}
                    >
                        {virtualItems.map((virtualRow) => {
                            const item = items[virtualRow.index];
                            return (
                                <tr
                                    key={virtualRow.key}
                                    style={{
                                        position: 'absolute',
                                        top: 0,
                                        left: 0,
                                        width: '100%',
                                        height: `${virtualRow.size}px`,
                                        transform: `translateY(${virtualRow.start}px)`
                                    }}
                                >
                                    {renderRow(item, virtualRow.index)}
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

export default VirtualizedTable;

