import React from 'react';
import {
    ChevronDown, ChevronRight, FileText, GitBranch, LayoutGrid, MapPin, History
} from 'lucide-react';
import clsx from 'clsx';
import { AuditLogEntry, GroupedAuditLogEntry, AuditAction } from '@/types/audit';
import {
