export const AuditLogRow: React.FC<AuditLogRowProps> = ({
    log,
    isExpanded,
    onToggle,
    compactView
}) => {
    const bedId = (log.details?.bedId as string) || '';
    const patientName = (log.details?.patientName as string) || '';
    const isGroup = (log as any as GroupedAuditLogEntry).isGroup;

    return (
