                            actionColors[log.action as AuditAction] || "bg-slate-50 text-slate-700 border-slate-100"
                        )}>
                            {actionIcons[log.action as AuditAction]}
                            {AUDIT_ACTION_LABELS[log.action as AuditAction]}
                        </span>
                    </td>
                )}
                {/* Resumen (HUMAN READABLE) */}
