                            </div>
                        ) : (
                            <span className="text-slate-300">-</span>
                        )}
                    </td>
                )}
            </tr>

            {/* Grouped Details */}
            {isGroup && isExpanded && (
                <tr className="bg-amber-50/10">
                    <td colSpan={compactView ? 4 : 7} className="px-12 py-4 border-l-4 border-amber-500/30">
