import React, { useMemo, useCallback, useState } from 'react';
import { BEDS } from '@/constants';
import { PatientRow } from '@/features/census/components/PatientRow';
import { useDailyRecordData, useDailyRecordActions } from '@/context/DailyRecordContext';
import { useCensusActions } from './CensusActionsContext';
import { useConfirmDialog } from '@/context/UIContext';
import { useTableConfig, TableColumnConfig } from '@/context/TableConfigContext';
import { ResizableHeader } from '@/components/ui/ResizableHeader';
import { Trash2, FileText, Stethoscope } from 'lucide-react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { PatientData, BedDefinition } from '@/types';
import clsx from 'clsx';

// Type for diagnosis input mode
export type DiagnosisMode = 'free' | 'cie10';

interface CensusTableProps {
    currentDateString: string;
    readOnly?: boolean;
}

export const CensusTable: React.FC<CensusTableProps> = ({
    currentDateString,
    readOnly = false
}) => {
    const { record } = useDailyRecordData();
    const { resetDay } = useDailyRecordActions();
    const { handleRowAction } = useCensusActions();
    const { confirm } = useConfirmDialog();
    const { config, isEditMode, updateColumnWidth } = useTableConfig();

    // Diagnosis mode: 'free' (text libre) or 'cie10' (CIE-10 search)
    const [diagnosisMode, setDiagnosisMode] = useState<DiagnosisMode>(() => {
        if (typeof localStorage !== 'undefined') {
            return (localStorage.getItem('hhr_diagnosis_mode') as DiagnosisMode) || 'free';
        }
        return 'free';
    });

    const toggleDiagnosisMode = useCallback(() => {
        const newMode: DiagnosisMode = diagnosisMode === 'free' ? 'cie10' : 'free';
        setDiagnosisMode(newMode);
        localStorage.setItem('hhr_diagnosis_mode', newMode);
    }, [diagnosisMode]);

    // Filter beds to display: All normal beds + Enabled extra beds
    const visibleBeds = useMemo(() => {
        if (!record) return [];
        const activeExtras = record.activeExtraBeds || [];
        return BEDS.filter(b => !b.isExtra || activeExtras.includes(b.id));
    }, [record]);

    // Flatten rows for virtualization (Main and Sub rows)
    const flatRows = useMemo(() => {
        if (!record) return [];
        const rows: { id: string; bed: BedDefinition; data: PatientData; isSubRow: boolean }[] = [];

        visibleBeds.forEach(bed => {
            const bedData = record.beds[bed.id];
            rows.push({ id: bed.id, bed, data: bedData, isSubRow: false });

            // Add clinical crib as a separate row item if it exists and bed isn't blocked
            if (bedData && bedData.clinicalCrib && !bedData.isBlocked) {
                rows.push({
                    id: `${bed.id}-cuna`,
                    bed,
                    data: bedData.clinicalCrib,
                    isSubRow: true
                });
            }
        });

        return rows;
    }, [record, visibleBeds]);

    const parentRef = React.useRef<HTMLDivElement>(null);

    const rowVirtualizer = useVirtualizer({
        count: flatRows.length,
        getScrollElement: () => parentRef.current,
        estimateSize: (index) => {
            const row = flatRows[index];
            // Main rows are slightly taller if they have many wrap-around inputs
            // But base height is standard.
            return row.isSubRow ? 40 : 44;
        },
        overscan: 10,
    });

    const handleClearAll = useCallback(async () => {
        const confirmed = await confirm({
            title: '⚠️ Reiniciar registro del día',
            message: '¿Está seguro de que desea ELIMINAR todos los datos del día?\n\nEsto eliminará el registro completo y podrá crear uno nuevo (copiar del anterior o en blanco).',
            confirmText: 'Sí, reiniciar',
            cancelText: 'Cancelar',
            variant: 'danger'
        });

        if (confirmed) {
            resetDay();
        }
    }, [confirm, resetDay]);

    const handleColumnResize = useCallback((column: keyof TableColumnConfig) => (width: number) => {
        updateColumnWidth(column, width);
    }, [updateColumnWidth]);

    const { columns } = config;
    const totalWidth = useMemo(() => {
        return Object.values(columns).reduce((sum, w) => sum + w, 0);
    }, [columns]);

    if (!record) return null;

    // Common header classes
    const headerClass = "sticky top-0 z-20 bg-slate-50 py-1 px-1 border-r border-slate-100 text-center text-slate-500 text-[10px] uppercase tracking-wider font-bold shadow-sm";

    return (
        <div className="card print:border-none print:shadow-none flex flex-col overflow-hidden">
            <div
                ref={parentRef}
                className="relative overflow-auto scrollbar-thin scrollbar-thumb-slate-300 scrollbar-track-transparent h-[calc(100vh-280px)] min-h-[400px]"
            >
                <table
                    data-testid="census-table"
                    className="text-left border-collapse print:text-xs relative text-[12px] leading-tight table-fixed"
                    style={{ width: `${totalWidth}px`, minWidth: '100%' }}
                >
                    <thead className="sticky top-0 z-30 bg-white">
                        <tr className="border-b border-slate-200 print:static">
                            {/* Action column - resizable */}
                            <ResizableHeader
                                width={columns.actions}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('actions')}
                                className={clsx(headerClass, "print:hidden")}
                            >
                                {!readOnly && (
                                    <button
                                        onClick={handleClearAll}
                                        className="p-1 rounded-md bg-slate-500/20 hover:bg-slate-500/40 text-slate-400 hover:text-slate-600 transition-all mx-auto block"
                                        title="Limpiar todos los datos del día"
                                    >
                                        <Trash2 size={12} />
                                    </button>
                                )}
                            </ResizableHeader>

                            {/* Bed column */}
                            <ResizableHeader
                                width={columns.bed}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('bed')}
                                className={headerClass}
                            >
                                <div className="flex flex-col items-center gap-0.5">
                                    <span>Cama</span>
                                </div>
                            </ResizableHeader>

                            {/* Type column */}
                            <ResizableHeader
                                width={columns.type}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('type')}
                                className={headerClass}
                            >
                                Tipo
                            </ResizableHeader>

                            {/* Name column */}
                            <ResizableHeader
                                width={columns.name}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('name')}
                                className={headerClass}
                            >
                                Nombre Paciente
                            </ResizableHeader>

                            {/* RUT column */}
                            <ResizableHeader
                                width={columns.rut}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('rut')}
                                className={headerClass}
                            >
                                RUT
                            </ResizableHeader>

                            {/* Age column */}
                            <ResizableHeader
                                width={columns.age}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('age')}
                                className={headerClass}
                            >
                                Edad
                            </ResizableHeader>

                            {/* Diagnosis column */}
                            <ResizableHeader
                                width={columns.diagnosis}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('diagnosis')}
                                className={headerClass}
                            >
                                <div className="flex items-center justify-center gap-1">
                                    <span>Diagnóstico</span>
                                    {!readOnly && (
                                        <button
                                            onClick={toggleDiagnosisMode}
                                            className={clsx(
                                                "text-[10px] flex items-center justify-center p-0.5 rounded transition-all print:hidden w-4 h-4",
                                                diagnosisMode === 'cie10'
                                                    ? "bg-medical-600 text-white"
                                                    : "bg-white border border-slate-300 text-slate-400 hover:text-medical-600"
                                            )}
                                            title={diagnosisMode === 'cie10' ? 'Modo CIE-10 (clic para cambiar a texto libre)' : 'Modo texto libre (clic para cambiar a CIE-10)'}
                                        >
                                            {diagnosisMode === 'cie10' ? <Stethoscope size={10} /> : <FileText size={10} />}
                                        </button>
                                    )}
                                </div>
                            </ResizableHeader>

                            {/* Specialty column */}
                            <ResizableHeader
                                width={columns.specialty}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('specialty')}
                                className={headerClass}
                            >
                                Esp
                            </ResizableHeader>

                            {/* Status column */}
                            <ResizableHeader
                                width={columns.status}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('status')}
                                className={headerClass}
                            >
                                Estado
                            </ResizableHeader>

                            {/* Admission column */}
                            <ResizableHeader
                                width={columns.admission}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('admission')}
                                className={headerClass}
                            >
                                Ingreso
                            </ResizableHeader>

                            {/* DMI column */}
                            <ResizableHeader
                                width={columns.dmi}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('dmi')}
                                className={headerClass}
                                title="Dispositivos médicos invasivos"
                            >
                                DMI
                            </ResizableHeader>

                            {/* C.QX column */}
                            <ResizableHeader
                                width={columns.cqx}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('cqx')}
                                className={headerClass}
                                title="Comp. Quirurgica"
                            >
                                C.QX
                            </ResizableHeader>

                            {/* UPC column */}
                            <ResizableHeader
                                width={columns.upc}
                                isEditMode={isEditMode}
                                onResize={handleColumnResize('upc')}
                                className={clsx(headerClass, "border-r-0")}
                            >
                                UPC
                            </ResizableHeader>
                        </tr>
                    </thead>
                    <tbody
                        className="relative"
                        style={{
                            height: `${rowVirtualizer.getTotalSize()}px`,
                            display: 'block'
                        }}
                    >
                        {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                            const row = flatRows[virtualRow.index];
                            return (
                                <PatientRow
                                    key={row.id}
                                    bed={row.bed}
                                    data={row.data}
                                    currentDateString={currentDateString}
                                    onAction={handleRowAction}
                                    readOnly={readOnly}
                                    actionMenuAlign={virtualRow.index >= flatRows.length - 4 ? 'bottom' : 'top'}
                                    diagnosisMode={diagnosisMode}
                                    isSubRow={row.isSubRow}
                                    style={{
                                        position: 'absolute',
                                        top: 0,
                                        left: 0,
                                        width: '100%',
                                        height: `${virtualRow.size}px`,
                                        transform: `translateY(${virtualRow.start}px)`,
                                        display: 'flex'
                                    }}
                                />
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

import React from 'react';
import clsx from 'clsx';
import { X } from 'lucide-react';
import { SPECIALTY_OPTIONS } from '@/constants';
import { DebouncedInput } from '@/components/ui/DebouncedInput';
import { BaseCellProps, EventTextHandler } from './inputCellTypes';

interface SpecialtySelectProps extends BaseCellProps {
    onChange: EventTextHandler;
}

export const SpecialtySelect: React.FC<SpecialtySelectProps> = ({
    data,
    isSubRow = false,
    isEmpty = false,
    readOnly = false,
    onChange
}) => {
    const isOther = data.specialty && !SPECIALTY_OPTIONS.includes(data.specialty as any);

    if (isEmpty && !isSubRow) {
        return (
            <td className="py-0.5 px-1 border-r border-slate-200 w-28 text-center">
                <div className="w-full py-0.5 px-1 border border-slate-200 rounded bg-slate-100 text-slate-400 text-[10px] italic">
                    -
                </div>
            </td>
        );
    }

    return (
        <td className="py-0.5 px-1 border-r border-slate-200 w-28 relative group/spec">
            {isOther || data.specialty === 'Otro' ? (
                <div className="relative">
                    <DebouncedInput
                        type="text"
                        className={clsx(
                            "w-full p-0.5 h-7 border border-slate-200 rounded focus:ring-2 focus:ring-medical-500/20 focus:border-medical-500 focus:outline-none text-[11px] bg-slate-50 font-medium",
                            isSubRow && "h-6"
                        )}
                        value={data.specialty === 'Otro' ? '' : (data.specialty || '')}
                        onChange={(val) => {
                            const syntheticEvent = { target: { value: val } } as React.ChangeEvent<HTMLInputElement>;
                            onChange('specialty')(syntheticEvent);
                        }}
                        placeholder="Especifique..."
                        autoFocus
                        disabled={readOnly}
                    />
                    {!readOnly && (
                        <button
                            onClick={() => {
                                const syntheticEvent = { target: { value: '' } } as React.ChangeEvent<HTMLInputElement>;
                                onChange('specialty')(syntheticEvent);
                            }}
                            className="absolute right-1 top-1/2 -translate-y-1/2 p-0.5 text-slate-400 hover:text-red-500 bg-white/80 rounded"
                        >
                            <X size={10} />
                        </button>
                    )}
                </div>
            ) : (
                <select
                    className={clsx(
                        "w-full p-0.5 h-7 border border-slate-200 rounded transition-all duration-200 focus:ring-2 focus:ring-medical-500/20 focus:border-medical-500 focus:outline-none text-[11px] bg-white cursor-pointer",
                        isSubRow && "h-6"
                    )}
                    value={data.specialty || ''}
                    onChange={onChange('specialty')}
                    disabled={readOnly}
                >
                    <option value="">-- Esp --</option>
                    {SPECIALTY_OPTIONS.map(opt => (
                        <option key={opt} value={opt}>{opt}</option>
                    ))}

                </select>
            )}
        </td>
    );
};

import React from 'react';
