        loading,
        showOriginal,
        showImportModal,
        setShowImportModal,
        importMessage,
        setImportMessage,
        importing,
        importError,
        fetching,
        fetchResult,
        handleImport,
        handleFetchFromGroup,
        toggleViewMode
    } = useShiftPanel();

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <RefreshCw className="w-8 h-8 animate-spin text-blue-500" />
            </div>
        );
    }

    if (!shift) {
