import { useState, useEffect, useCallback } from 'react';
import { onAuthChange, signOut, AuthUser, hasActiveFirebaseSession, signInAnonymouslyForPassport } from '@/services/auth/authService';
import {
    getStoredPassport,
    validatePassport,
    clearStoredPassport,
    isEligibleForPassport,
    downloadPassport
} from '@/services/auth/passportService';
import { logUserLogout, logUserLogin } from '@/services/admin/auditService';
import { getSetting, saveSetting } from '@/services/storage/indexedDBService';

/**
 * Available user roles in the application.
 * Controls access to different modules and features.
 * 
 * - `viewer`: Read-only access to all data
 * - `editor`: Can modify patient data and daily records
 * - `admin`: Full access including system configuration
 * - `nurse_hospital`: Hospital nurse with edit permissions (from passport)
 * - `doctor_urgency`: Emergency doctor with limited edit access
 * - `viewer_census`: Can only view census data
 */
export type UserRole = 'viewer' | 'editor' | 'admin' | 'nurse_hospital' | 'doctor_urgency' | 'viewer_census';

/**
 * Return type for the useAuthState hook.
 * Provides user authentication state, role information, and auth actions.
 */
export interface UseAuthStateReturn {
    /** Current authenticated user or null if not logged in */
    user: AuthUser | null;
    /** True while authentication state is being determined */
    authLoading: boolean;
    /** True if connected to Firebase (either real or anonymous auth) */
    isFirebaseConnected: boolean;
    /** Signs out the current user (clears Firebase and passport auth) */
    handleLogout: () => Promise<void>;

    // Role-based properties
    /** Current user's role */
    role: UserRole;
    /** True if user has edit permissions (editor, admin, or nurse_hospital) */
    isEditor: boolean;
    /** True if user only has view permissions */
    isViewer: boolean;
    /** Alias for isEditor - true if user can modify data */
    canEdit: boolean;

    // Offline passport properties
    /** True if using offline passport authentication (no Firebase) */
    isOfflineMode: boolean;
    /** True if current user can generate offline passports (admin only) */
    canDownloadPassport: boolean;
    /** Downloads a passport file for offline access with specified role */
    handleDownloadPassport: (role: string) => Promise<boolean>;
}

import { SESSION_TIMEOUT_MS, ACTIVITY_EVENTS } from '@/constants/security';

/**
 * useAuthState Hook
 * 
 * Central hook for managing authentication state throughout the application.
 * Supports dual authentication modes:
 * 
 * 1. **Firebase Auth**: Standard email/password authentication with real-time sync
 * 2. **Offline Passport**: Encrypted token-based auth for offline/island access
 * 
 * The hook automatically detects stored passports on mount and validates them.
 * Firebase connection status is monitored to enable/disable sync features.
 * 
 * @returns Authentication state, user info, role flags, and auth actions
 */
export const useAuthState = (): UseAuthStateReturn => {
    const [user, setUser] = useState<AuthUser | null>(null);
    const [authLoading, setAuthLoading] = useState(true);
    const [isFirebaseConnected, setIsFirebaseConnected] = useState(false);
    const [isOfflineMode, setIsOfflineMode] = useState(false);
    const [isOnline, setIsOnline] = useState(window.navigator.onLine);

    // ========================================================================
    // Authentication Actions
    // ========================================================================

    /**
     * Performs a full sign-out, clearing both Firebase sessions and local passport tokens.
     * 
     * @param reason - Whether the logout was 'manual' (user clicked) or 'automatic' (session timeout).
     */
    const handleLogout = useCallback(async (reason: 'manual' | 'automatic' = 'manual') => {
        // Log the logout event before clearing data
        if (user?.email) {
            await logUserLogout(user.email, reason);
        }

        // Clear offline data
        await clearStoredPassport();
        await saveSetting('hhr_offline_user', null);
        localStorage.removeItem('hhr_offline_user'); // Cleanup

        // Reset login flag for audit tracking
        if (typeof sessionStorage !== 'undefined') {
            sessionStorage.removeItem('hhr_logged_this_session');
        }

        setIsOfflineMode(false);

        // Firebase sign out (may fail if offline, that's ok)
        try {
            await signOut();
        } catch (error) {
            console.warn('[useAuthState] Firebase signOut failed (probably offline):', error);
        }

        setUser(null);
    }, [user]);

    // ========================================================================
    // Inactivity Detection (MINSAL Requirement)
    // ========================================================================
    useEffect(() => {
        if (!user) return;

        let timeoutId: NodeJS.Timeout;

        const resetTimer = () => {
            if (timeoutId) clearTimeout(timeoutId);
            timeoutId = setTimeout(() => {
                console.warn('[useAuthState] Logout due to inactivity');
                handleLogout('automatic');
            }, SESSION_TIMEOUT_MS);
        };

        // Add activity listeners
        ACTIVITY_EVENTS.forEach(event => {
            window.addEventListener(event, resetTimer);
        });

        // Initial timer start
        resetTimer();

        return () => {
            if (timeoutId) clearTimeout(timeoutId);
            ACTIVITY_EVENTS.forEach(event => {
                window.removeEventListener(event, resetTimer);
            });
        };
    }, [user, handleLogout]);

    // Network status listeners
    useEffect(() => {
        const handleOnline = async () => {
            // console.debug('[useAuthState] Network is ONLINE');
            setIsOnline(true);
            const storedUser = await getSetting<AuthUser | null>('hhr_offline_user', null);
            if (storedUser) {
                signInAnonymouslyForPassport().catch((err: unknown) =>
                    console.warn('[useAuthState] Proactive re-auth failed:', err)
                );
            }
        };

        const handleOffline = () => {
            // console.debug('[useAuthState] Network is OFFLINE');
            setIsOnline(false);
        };

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    // Check for offline passport user on mount
    useEffect(() => {
        // 0. E2E Fast Path: Immediate auth if in VRT/E2E mode
        if (typeof window !== 'undefined' && (window as any).__HHR_E2E_OVERRIDE__) {
            const storedUser = localStorage.getItem('hhr_offline_user');
            if (storedUser) {
                try {
                    setUser(JSON.parse(storedUser));
                    setIsOfflineMode(true);
                    setAuthLoading(false);
                    return;
                } catch (e) {
                    console.error('[E2E] Failed to parse E2E user:', e);
                }
            }
        }

        // console.debug('[useAuthState] 🚀 Initializing Auth System...');

        const checkOfflineUser = async () => {
            // console.debug('[useAuthState] 🔍 Checking local storage for offline user...');
            try {
                let offlineUser = await getSetting<AuthUser | null>('hhr_offline_user', null);

                // Fallback for migration
                if (!offlineUser) {
                    const legacy = localStorage.getItem('hhr_offline_user');
                    if (legacy) {
                        offlineUser = JSON.parse(legacy);
                        await saveSetting('hhr_offline_user', offlineUser);
                    }
                }

                if (offlineUser) {
                    const passport = await getStoredPassport();
                    if (passport) {
                        const result = await validatePassport(passport);
                        if (result.valid) {
                            // console.debug('[useAuthState] ✅ Valid offline passport found');
                            setUser(offlineUser);
                            setIsOfflineMode(true);
                            setAuthLoading(false);
                            return true;
                        } else {
                            console.warn('[useAuthState] ❌ Stored passport is invalid:', result.error);
                            await clearStoredPassport();
                            await saveSetting('hhr_offline_user', null);
                            localStorage.removeItem('hhr_offline_user');
                        }
                    }
                }
            } catch (error) {
                console.error('[useAuthState] ‼️ Error checking offline user:', error);
            }
            return false;
        };

        const initAuth = async () => {
            // console.debug('[useAuthState] 📡 Subscribing to Firebase Auth changes...');

            // Subscribe to Firebase Auth first (higher priority)
            const unsubscribe = onAuthChange(async (authUser) => {
                // console.debug('[useAuthState] 🔔 Auth State Change received:', authUser ? authUser.email : 'NULL');

                if (authUser) {
                    const isAnonymousUser = authUser.email === null;
                    const email = authUser.email;

                    if (!isAnonymousUser && email) {
                        if (typeof sessionStorage !== 'undefined' && !sessionStorage.getItem('hhr_logged_this_session')) {
                            logUserLogin(email);
                            sessionStorage.setItem('hhr_logged_this_session', 'true');
                        }
                    }

                    if (isAnonymousUser) {
                        const passportUser = await getSetting<AuthUser | null>('hhr_offline_user', null);
                        if (passportUser) {
                            setUser(passportUser);
                            setIsOfflineMode(false);
                        } else {
                            setUser(authUser);
                            setIsOfflineMode(false);
                        }
                    } else {
                        // console.debug('[useAuthState] 👤 Real Google user detected. Overriding any local passport.');
                        setUser(authUser);
                        setIsOfflineMode(false);
                        await saveSetting('hhr_offline_user', null);
                        localStorage.removeItem('hhr_offline_user');
                        await clearStoredPassport();
                    }
                } else {
                    // console.debug('[useAuthState] 👤 Firebase user is NULL, checking offline fallback...');
                    // Only check offline if Firebase reports no user
                    const hasOffline = await checkOfflineUser();
                    if (!hasOffline) {
                        setUser(null);
                    }
                }

                // console.debug('[useAuthState] ✨ Auth transition finished');
                setAuthLoading(false);
            });

            return unsubscribe;
        };

        let unsubscribe: (() => void) | undefined;

        // Safety timeout: If Firebase takes too long (e.g. network issues), stop loading
        // Shorter timeout if we're already offline to show LoginPage faster
        const timeoutMs = window.navigator.onLine ? 8000 : 3000;
        const safetyTimeout = setTimeout(() => {
            console.warn(`[useAuthState] ⚠️ Auth initialization timed out (${timeoutMs}ms) - forcing load completion`);
            setAuthLoading(false);
        }, timeoutMs);

        initAuth().then(unsub => {
            if (unsub) unsubscribe = unsub;
        });

        return () => {
            // console.debug('[useAuthState] 🧹 Cleaning up Auth subscription');
            clearTimeout(safetyTimeout);
            if (unsubscribe) unsubscribe();
        };
    }, []);

    useEffect(() => {
        const checkConnection = () => {
            const hasSession = hasActiveFirebaseSession();
            setIsFirebaseConnected(isOnline && (hasSession || (!!user && !isOfflineMode)));
        };

        checkConnection();
        const interval = setInterval(checkConnection, 1000);
        const timeout = setTimeout(() => clearInterval(interval), 10000);

        return () => {
            clearInterval(interval);
            clearTimeout(timeout);
        };
    }, [user, isOfflineMode, isOnline]);

    /**
     * Generates and downloads a passport file for the current user.
     * Only admin can generate passports.
     * 
     * @param role - The role to assign: 'admin' or 'nurse_hospital'
     * @returns True if the download was successful, false otherwise.
     */
    const handleDownloadPassport = useCallback(async (role: string) => {
        if (!user) return false;
        return await downloadPassport(user, role);
    }, [user]);

    const role: UserRole = (user?.role as UserRole) || 'viewer';
    const isEditor = role === 'editor' || role === 'admin' || role === 'nurse_hospital';
    const isViewer = !isEditor;
    const canEdit = isEditor;
    const canDownloadPassport = isEligibleForPassport(user);

    return {
        user,
        authLoading,
        isFirebaseConnected,
        handleLogout,
        role,
        isEditor,
        isViewer,
        canEdit,
        isOfflineMode,
        canDownloadPassport,
        handleDownloadPassport,
    };
};

import { useCallback } from 'react';
import { DailyRecord, PatientData, CudyrScore, PatientFieldValue, DailyRecordPatch } from '@/types';
import { usePatientValidation } from './usePatientValidation';
import { useBedAudit } from './useBedAudit';
import { BedAction, bedManagementReducer } from './useBedManagementReducer';


/**
 * Interface defining the actions available for bed management.
 */
export interface BedManagementActions {
    /**
     * Updates a single field for a patient in a specific bed.
     * Includes validation and audit logging for admissions.
     */
    updatePatient: (bedId: string, field: keyof PatientData, value: PatientFieldValue) => void;

    /**
     * Updates multiple patient fields atomically.
     */
    updatePatientMultiple: (bedId: string, fields: Partial<PatientData>) => void;

    /**
     * Updates a specific field in the CUDYR score for a patient.
     */
    updateCudyr: (bedId: string, field: keyof CudyrScore, value: number) => void;

    /**
     * Manages clinical crib operations (create, remove, or update fields).
     */
    updateClinicalCrib: (bedId: string, field: keyof PatientData | 'create' | 'remove', value?: PatientFieldValue) => void;

    /**
     * Updates multiple clinical crib fields atomically.
     */
    updateClinicalCribMultiple: (bedId: string, fields: Partial<PatientData>) => void;

    /**
     * Updates a specific field in the CUDYR score for a clinical crib.
     */
    updateClinicalCribCudyr: (bedId: string, field: keyof CudyrScore, value: number) => void;

    /**
     * Clears patient data from a bed (Discharge/Cleanup).
     */
    clearPatient: (bedId: string) => void;

    /**
     * Clears all beds in the current record.
     */
    clearAllBeds: () => void;

    /**
     * Moves or copies a patient from one bed to another.
     */
    moveOrCopyPatient: (type: 'move' | 'copy', sourceBedId: string, targetBedId: string) => void;

    /**
     * Toggles the blocked status of a bed with an optional reason.
     */
    toggleBlockBed: (bedId: string, reason?: string) => void;
    updateBlockedReason: (bedId: string, reason: string) => void;

    /**
     * Toggles an extra bed visibility.
     */
    toggleExtraBed: (bedId: string) => void;
}

// ============================================================================
// Hook Implementation
// ============================================================================

// ============================================================================
// Hook Implementation
// ============================================================================

/**
 * useBedManagement Hook
 * 
 * Orchestrates all bed-related operations using a Redux-style reducer pattern.
 * This simplifies delegation and makes state transitions predictable.
 */
export const useBedManagement = (
    record: DailyRecord | null,
    saveAndUpdate: (updatedRecord: DailyRecord) => void, // Kept for legacy compat if needed, but reducer uses patches
    patchRecord: (partial: DailyRecordPatch) => Promise<void>
): BedManagementActions => {
    const validation = usePatientValidation();
    const bedAudit = useBedAudit(record);

    // ========================================================================
    // Dispatcher
    // ========================================================================

    const dispatch = useCallback((action: BedAction) => {
        if (!record) return;

        // 1. Validation (for specific actions)
        if (action.type === 'UPDATE_PATIENT') {
            const result = validation.processFieldValue(action.field, action.value);
            if (!result.valid) {
                console.warn(`Validation failed for ${action.field}:`, result.error);
                return;
            }
            action.value = result.value;
        } else if (action.type === 'UPDATE_PATIENT_MULTIPLE') {
            // Validate all fields in the batch
            const validatedFields: Partial<PatientData> = {};
            for (const [key, value] of Object.entries(action.fields)) {
                const result = validation.processFieldValue(key as keyof PatientData, value as PatientFieldValue);
                if (result.valid) {
                    validatedFields[key as keyof PatientData] = result.value as any; // Cast here temporarily because processFieldValue returns PatientFieldValue which is a union
                }
            }
            action.fields = validatedFields;
        }

        // 2. Audit Logging
        // We log *before* applying the patch to capture the intent
        try {
            switch (action.type) {
                case 'UPDATE_PATIENT':
                    bedAudit.auditPatientChange(action.bedId, action.field, record.beds[action.bedId], action.value);
                    break;
                case 'UPDATE_CUDYR':
                    bedAudit.auditCudyrChange(action.bedId, action.field, action.value);
                    break;
                case 'UPDATE_CLINICAL_CRIB_CUDYR':
                    bedAudit.auditCribCudyrChange(action.bedId, action.field, action.value);
                    break;
                case 'CLEAR_PATIENT': {
                    const bed = record.beds[action.bedId];
                    if (bed.patientName) {
                        bedAudit.auditPatientCleared(action.bedId, bed.patientName, bed.rut);
                    }
                    break;
                }
                case 'TOGGLE_BLOCK_BED':
                    // Audit handled in reducer-like logic or separate audit hook? 
                    // For now, simple logging here or moving useBedOperations audit logic here.
                    // Ideally, audit should be decoupled (observer pattern), but we keep it direct for now.
                    break;
            }
        } catch (e) {
            console.error('Audit logging failed', e);
        }

        // 3. Reducer (Calculate Patch) & 4. Apply Patch
        try {
            const patch = bedManagementReducer(record, action);
            if (patch) {
                patchRecord(patch);
            }
        } catch (e) {
            console.warn('Bed management action failed:', e);
        }
    }, [record, validation, patchRecord, bedAudit]);

    // ========================================================================
    // Action Creators (Adapters to match BedManagementActions interface)
    // ========================================================================

    const updatePatient = useCallback((bedId: string, field: keyof PatientData, value: PatientFieldValue) => {
        dispatch({ type: 'UPDATE_PATIENT', bedId, field, value });
    }, [dispatch]);

    const updatePatientMultiple = useCallback((bedId: string, fields: Partial<PatientData>) => {
        dispatch({ type: 'UPDATE_PATIENT_MULTIPLE', bedId, fields });
    }, [dispatch]);

    const updateCudyr = useCallback((bedId: string, field: keyof CudyrScore, value: number) => {
        dispatch({ type: 'UPDATE_CUDYR', bedId, field, value });
    }, [dispatch]);

    const updateClinicalCrib = useCallback((bedId: string, field: keyof PatientData | 'create' | 'remove', value?: PatientFieldValue) => {
        if (field === 'create') {
            dispatch({ type: 'CREATE_CLINICAL_CRIB', bedId });
        } else if (field === 'remove') {
            dispatch({ type: 'REMOVE_CLINICAL_CRIB', bedId });
        } else {
            dispatch({ type: 'UPDATE_CLINICAL_CRIB', bedId, field, value: value! });
        }
    }, [dispatch]);

    const updateClinicalCribMultiple = useCallback((bedId: string, fields: Partial<PatientData>) => {
        dispatch({ type: 'UPDATE_CLINICAL_CRIB_MULTIPLE', bedId, fields });
    }, [dispatch]);

    const updateClinicalCribCudyr = useCallback((bedId: string, field: keyof CudyrScore, value: number) => {
        dispatch({ type: 'UPDATE_CLINICAL_CRIB_CUDYR', bedId, field, value });
    }, [dispatch]);

    const clearPatient = useCallback((bedId: string) => {
        dispatch({ type: 'CLEAR_PATIENT', bedId });
    }, [dispatch]);

    // Legacy bulk operation - handled separately or via reducer loop?
    // It's cleaner to keep the clearAll logic in reducer if possible, but BEDS dependency makes it tricky
    // Re-using the logic from useBedOperations but wrapped
    const clearAllBeds = useCallback(() => {
        dispatch({ type: 'CLEAR_ALL_BEDS' });
    }, [dispatch]);

    const moveOrCopyPatient = useCallback((type: 'move' | 'copy', sourceBedId: string, targetBedId: string) => {
        if (type === 'move') dispatch({ type: 'MOVE_PATIENT', sourceBedId, targetBedId });
        else dispatch({ type: 'COPY_PATIENT', sourceBedId, targetBedId });
    }, [dispatch]);

    const toggleBlockBed = useCallback((bedId: string, reason?: string) => {
        dispatch({ type: 'TOGGLE_BLOCK_BED', bedId, reason });
    }, [dispatch]);

    const updateBlockedReason = useCallback((bedId: string, reason: string) => {
        dispatch({ type: 'UPDATE_BLOCKED_REASON', bedId, reason });
    }, [dispatch]);

    const toggleExtraBed = useCallback((bedId: string) => {
        dispatch({ type: 'TOGGLE_EXTRA_BED', bedId });
    }, [dispatch]);

    return {
        updatePatient,
        updatePatientMultiple,
        updateCudyr,
        updateClinicalCrib,
        updateClinicalCribMultiple,
        updateClinicalCribCudyr,
        clearPatient,
        clearAllBeds, // This needs fixing in reducer or here
        moveOrCopyPatient,
        toggleBlockBed,
        updateBlockedReason,
        toggleExtraBed
    };
};

