import React, { useState, useMemo } from 'react';

/**
 * Return type for useDateNavigation hook.
 * Provides date selection state and derived values for navigation.
 */
export interface UseDateNavigationReturn {
    /** Currently selected year (e.g., 2024) */
    selectedYear: number;
    /** Set the selected year */
    setSelectedYear: React.Dispatch<React.SetStateAction<number>>;
    /** Currently selected month (0-11, where 0 = January) */
    selectedMonth: number;
    /** Set the selected month */
    setSelectedMonth: React.Dispatch<React.SetStateAction<number>>;
    /** Currently selected day of month (1-31) */
    selectedDay: number;
    /** Set the selected day */
    setSelectedDay: React.Dispatch<React.SetStateAction<number>>;
    /** Number of days in the currently selected month */
    daysInMonth: number;
    /** Formatted date string in YYYY-MM-DD format */
    currentDateString: string;
}

/**
 * useDateNavigation Hook
 * 
 * Manages the date selection state for navigating between daily records.
 * Provides year, month, and day state with setters, plus derived values
 * like days in month and formatted date string.
 * 
 * Initializes to the current date on mount.
 * 
 * @returns Date selection state and setters
 * 
 * @example
 * ```tsx
 * const {
 *     selectedYear, setSelectedYear,
 *     selectedMonth, setSelectedMonth,
 *     selectedDay, setSelectedDay,
 *     currentDateString
 * } = useDateNavigation();
 * 
 * // currentDateString = "2024-12-27"
 * ```
 */
export const useDateNavigation = (): UseDateNavigationReturn => {
    // 0. Resolve initial date from URL or System
    const initialDate = useMemo(() => {
        if (typeof window !== 'undefined') {
            const params = new URLSearchParams(window.location.search);
            const dateParam = params.get('date');
            if (dateParam && /^\d{4}-\d{2}-\d{2}$/.test(dateParam)) {
                const [y, m, d] = dateParam.split('-').map(Number);
                const dObj = new Date(y, m - 1, d);
                if (!isNaN(dObj.getTime())) return dObj;
            }
        }
        return new Date();
    }, []);

    // Date Selection State
    const [selectedYear, setSelectedYear] = useState<number>(initialDate.getFullYear());
    const [selectedMonth, setSelectedMonth] = useState<number>(initialDate.getMonth()); // 0-11
    const [selectedDay, setSelectedDay] = useState<number>(initialDate.getDate());

    // Calculate days in selected month
    const daysInMonth = useMemo(() => {
        return new Date(selectedYear, selectedMonth + 1, 0).getDate();
    }, [selectedYear, selectedMonth]);

    // Format current date as YYYY-MM-DD
    const currentDateString = useMemo(() => {
        const y = selectedYear;
        const m = String(selectedMonth + 1).padStart(2, '0');
        const d = String(selectedDay).padStart(2, '0');
        return `${y}-${m}-${d}`;
    }, [selectedYear, selectedMonth, selectedDay]);

    return {
        selectedYear,
        setSelectedYear,
        selectedMonth,
        setSelectedMonth,
        selectedDay,
        setSelectedDay,
        daysInMonth,
        currentDateString
    };
};

/**
 * useExcelParser Hook
 * 
 * Extracted from SharedCensusView.tsx to handle Excel file parsing with ExcelJS.
 * Supports multiple sheets, merged cells (colSpan/rowSpan), and rich text values.
 * 
 * This hook is reusable for any Excel viewing functionality in the application.
 */

import { useState, useCallback, useRef, useEffect } from 'react';
import { createWorkbook } from '@/services/exporters/excelUtils';

// ============================================================================
// Types
// ============================================================================

interface ExcelRichText {
    text: string;
}

interface ExcelFormula {
    formula?: string;
    result?: unknown;
}

interface ExcelErrorValue {
    error: string;
}

export interface ParsedCell {
    value: string | number | Date | null | boolean;
    colSpan: number;
    rowSpan: number;
    hidden: boolean;
}

export interface UseExcelParserReturn {
    // Data
    workbookData: Record<string, ParsedCell[][]>;
    sheetNames: string[];
    activeSheet: string;
    setActiveSheet: (sheet: string) => void;

    // Loading state
    isParsing: boolean;
    parseError: string | null;

    // Actions
    parseFromUrl: (url: string) => Promise<void>;
    parseFromBlob: (blob: Blob) => Promise<void>;
    reset: () => void;
}

// ============================================================================
// Hook Implementation
// ============================================================================

export function useExcelParser(): UseExcelParserReturn {
    const [workbookData, setWorkbookData] = useState<Record<string, ParsedCell[][]>>({});
    const [sheetNames, setSheetNames] = useState<string[]>([]);
    const [activeSheet, setActiveSheet] = useState<string>('');
    const [isParsing, setIsParsing] = useState(false);
    const [parseError, setParseError] = useState<string | null>(null);

    // Check if component is mounted to avoid state updates after unmount
    const abortControllerRef = useRef<AbortController | null>(null);

    /**
     * Reset all parser state and abort pending requests
     */
    const reset = useCallback(() => {
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
            abortControllerRef.current = null;
        }
        setWorkbookData({});
        setSheetNames([]);
        setActiveSheet('');
        setParseError(null);
        setIsParsing(false);
    }, []);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (abortControllerRef.current) {
                abortControllerRef.current.abort();
            }
        };
    }, []);

    /**
     * Core parsing logic - processes a Blob into structured cell data
     * Note: This function is not cancellable once plain blob is received, 
     * but we check signal before setting state.
     */
    const parseFromBlob = useCallback(async (blob: Blob) => {
        setIsParsing(true);
        setParseError(null);
        setWorkbookData({});
        setSheetNames([]);
        setActiveSheet('');

        try {
            const workbook = await createWorkbook();
            const buffer = await blob.arrayBuffer();
            await workbook.xlsx.load(buffer);

            const allSheetsData: Record<string, ParsedCell[][]> = {};
            const names: string[] = [];

            workbook.eachSheet((worksheet) => {
                const sheetName = worksheet.name;
                names.push(sheetName);

                const grid: ParsedCell[][] = [];
                const rowsCount = worksheet.rowCount;
                const colsCount = worksheet.columnCount;
                const hiddenCells = new Set<string>();

                for (let r = 1; r <= rowsCount; r++) {
                    const rowGrid: ParsedCell[] = [];
                    const row = worksheet.getRow(r);

                    for (let c = 1; c <= colsCount; c++) {
                        const cellRef = `${r},${c}`;

                        // Skip cells that are part of a merge (not the master cell)
                        if (hiddenCells.has(cellRef)) {
                            rowGrid.push({ value: null, colSpan: 1, rowSpan: 1, hidden: true });
                            continue;
                        }

                        const cell = row.getCell(c);
                        let val = cell.value;

                        // Extract actual value from complex cell types
                        if (val && typeof val === 'object') {
                            if ('richText' in val && Array.isArray((val as { richText: unknown }).richText)) {
                                // Rich text - concatenate all text parts
                                val = ((val as { richText: ExcelRichText[] }).richText).map((rt) => rt.text).join('');
                            } else if ('formula' in val || 'result' in val) {
                                // Formula cell - get the result
                                const formulaRes = (val as ExcelFormula).result;
                                // Default to 0 if result is missing
                                val = (formulaRes === undefined || formulaRes === null) ? 0 : formulaRes as string | number | Date;
                            } else if ('text' in val) {
                                // Hyperlink or similar
                                val = (val as { text: string }).text;
                            }

                            // Handle if the extracted result is STILL an object
                            if (val && typeof val === 'object') {
                                if ('error' in val) {
                                    val = (val as ExcelErrorValue).error;
                                } else if (val instanceof Date) {
                                    // Keep as Date object
                                } else {
                                    // Fallback for unknown objects
                                    val = '';
                                }
                            }
                        }

                        // Ensure val is of allowed type or cast to string
                        let finalVal: string | number | Date | null | boolean = null;
                        if (val === null || val === undefined) finalVal = null;
                        else if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean' || val instanceof Date) {
                            finalVal = val;
                        } else {
                            finalVal = String(val);
                        }

                        let colSpan = 1;
                        let rowSpan = 1;

                        // Handle merged cells
                        if (cell.isMerged) {
                            const master = cell.master;

                            // If this is not the master cell, mark as hidden
                            if (master.address !== cell.address) {
                                rowGrid.push({ value: null, colSpan: 1, rowSpan: 1, hidden: true });
                                continue;
                            }

                            // Get merge range from worksheet internal data
                            const range = (worksheet as any)._merges?.[cell.address];
                            if (range) {
                                colSpan = range.right - range.left + 1;
                                rowSpan = range.bottom - range.top + 1;

                                // Mark all cells in the merge as hidden (except master)
                                for (let mr = range.top; mr <= range.bottom; mr++) {
                                    for (let mc = range.left; mc <= range.right; mc++) {
                                        if (mr === r && mc === c) continue;
                                        hiddenCells.add(`${mr},${mc}`);
                                    }
                                }
                            }
                        }

                        rowGrid.push({ value: finalVal, colSpan, rowSpan, hidden: false });
                    }
                    grid.push(rowGrid);
                }
                allSheetsData[sheetName] = grid;
            });

            setWorkbookData(allSheetsData);
            setSheetNames(names);
            if (names.length > 0) {
                setActiveSheet(names[0]);
            }
        } catch (err) {
            console.error('[useExcelParser] Error parsing excel:', err);
            setParseError('No se pudo cargar el archivo. Intenta descargarlo.');
        } finally {
            setIsParsing(false);
        }
    }, []);

    /**
     * Fetch and parse from a URL
     */
    const parseFromUrl = useCallback(async (url: string) => {
        // Abort previous request if any
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
        }

        const controller = new AbortController();
        abortControllerRef.current = controller;

        setIsParsing(true);
        setParseError(null);

        try {
            const response = await fetch(url, { signal: controller.signal });
            if (!response.ok) throw new Error(`Failed to fetch file: ${response.status}`);

            const blob = await response.blob();

            // Check if aborted during blob reading
            if (controller.signal.aborted) return;

            await parseFromBlob(blob);
        } catch (err: any) {
            if (err.name === 'AbortError') {
                console.warn('[useExcelParser] Fetch aborted');
                return;
            }
            console.error('[useExcelParser] Error fetching file:', err);
            setParseError('No se pudo descargar el archivo para visualización.');
            setIsParsing(false);
        } finally {
            // Only clear loading if this is the active request
            if (abortControllerRef.current === controller) {
                abortControllerRef.current = null;
                // Note: parseFromBlob handles its own setIsParsing(false), 
                // but if we errored/aborted before calling it, we need to handle it.
                // If success, parseFromBlob handles it.
                // Actually relying on parseFromBlob finally block is tricky if we don't call it.
                // We should ensure isParsing is false if we error here.
                // But parseFromBlob sets isParsing=true again.
            }
        }
    }, [parseFromBlob]);

    return {
        workbookData,
        sheetNames,
        activeSheet,
        setActiveSheet,
        isParsing,
        parseError,
        parseFromUrl,
        parseFromBlob,
        reset
    };
}

import { useState, useCallback } from 'react';
import { DailyRecordRepository } from '@/services/repositories/DailyRecordRepository';
import { PatientMasterRepository } from '@/services/repositories/PatientMasterRepository';
import { MasterPatient } from '@/types';
import { formatRut, isValidRut } from '@/utils/rutUtils';

export interface Conflict {
    rut: string;
    description: string;
    options: string[]; // List of different names found for this RUT
    records: string[]; // List of dates
    bedMap: Record<string, string>; // Mapping of date -> bedId for historical correction
}

export interface AnalysisResult {
    totalRecords: number;
    uniquePatients: number;
    validPatients: MasterPatient[];
    conflicts: Conflict[];
}

export const usePatientAnalysis = () => {
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [isMigrating, setIsMigrating] = useState(false);
    const [isHarmonizing, setIsHarmonizing] = useState(false);
    const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
    const [migrationResult, setMigrationResult] = useState<{ successes: number, errors: number } | null>(null);

    const resolveConflict = useCallback(async (rut: string, correctName: string, harmonizeHistory: boolean = false) => {
        if (!analysis) return;

        const conflict = analysis.conflicts.find(c => c.rut === rut);
        if (!conflict) return;

        if (harmonizeHistory) {
            setIsHarmonizing(true);
            try {
                const { logAuditEvent } = await import('@/services/admin/auditService');
                const { getCurrentUserEmail } = await import('@/services/admin/utils/auditUtils');

                // Correct each historical day
                for (const date of conflict.records) {
                    const bedId = conflict.bedMap[date];
                    if (!bedId) continue;

                    await DailyRecordRepository.updatePartial(date, {
                        [`beds.${bedId}.patientName`]: correctName
                    } as any);

                    // Audit the correction
                    await logAuditEvent(
                        getCurrentUserEmail(),
                        'PATIENT_HARMONIZED',
                        'dailyRecord',
                        date,
                        {
                            rut,
                            correctName,
                            previousName: conflict.options.filter(o => o !== correctName).join(', '),
                            bedId,
                            automated: true
                        },
                        rut,
                        date
                    );
                }
            } catch (error) {
                console.error("Harmonization failed", error);
            } finally {
                setIsHarmonizing(false);
            }
        }

        setAnalysis(prev => {
            if (!prev) return null;

            // 1. Update the patient record in the validPatients list
            const updatedPatients = prev.validPatients.map(p => {
                if (p.rut === rut) {
                    return { ...p, fullName: correctName, updatedAt: Date.now() };
                }
                return p;
            });

            // 2. Remove the conflict from the list
            const updatedConflicts = prev.conflicts.filter(c => c.rut !== rut);

            return {
                ...prev,
                validPatients: updatedPatients,
                conflicts: updatedConflicts
            };
        });
    }, [analysis]);

    const runAnalysis = useCallback(async () => {
        setIsAnalyzing(true);
        setAnalysis(null);
        setMigrationResult(null);

        try {
            const dates = await DailyRecordRepository.getAllDates();
            const sortedDates = [...dates].sort();

            const patientsMap = new Map<string, MasterPatient>();
            const conflicts: Conflict[] = [];

            // Temporary map to track active events per RUT during the scan
            // Key: RUT, Value: Current Open Event
            const activeEvents = new Map<string, {
                startDate: string;
                lastSeen: string;
                bedId: string;
                diagnosis: string;
            }>();

            for (const date of sortedDates) {
                const record = await DailyRecordRepository.getForDate(date);
                if (!record) continue;

                // 1. Process active beds to detect admissions and ongoing stays
                const bedsWithPatients = Object.entries(record.beds).filter(([_, p]) =>
                    p.rut && isValidRut(p.rut) && p.patientName
                );

                const rutsInCensusToday = new Set<string>();

                for (const [bedId, p] of bedsWithPatients) {
                    const normalizedRut = formatRut(p.rut).toUpperCase();
                    rutsInCensusToday.add(normalizedRut);

                    let master = patientsMap.get(normalizedRut);

                    if (!master) {
                        master = {
                            rut: normalizedRut,
                            fullName: p.patientName,
                            birthDate: p.birthDate,
                            forecast: p.insurance,
                            gender: p.biologicalSex,
                            hospitalizations: [],
                            vitalStatus: 'Vivo',
                            lastAdmission: p.admissionDate || date,
                            createdAt: Date.now(),
                            updatedAt: Date.now()
                        };
                        patientsMap.set(normalizedRut, master);
                    }

                    // Conflict check (Names) - Only if truly different (not just case/space)
                    if (master.fullName.trim().toLowerCase() !== p.patientName.trim().toLowerCase()) {
                        const existingConflict = conflicts.find(c => c.rut === normalizedRut);
                        if (!existingConflict) {
                            conflicts.push({
                                rut: normalizedRut,
                                description: `Diferencia de nombres detectada`,
                                options: Array.from(new Set([master.fullName, p.patientName])),
                                records: [date],
                                bedMap: { [date]: bedId }
                            });
                        } else {
                            if (!existingConflict.records.includes(date)) {
                                existingConflict.records.push(date);
                            }
                            if (!existingConflict.options.includes(p.patientName)) {
                                existingConflict.options.push(p.patientName);
                            }
                            existingConflict.bedMap[date] = bedId;
                        }
                    }

                    // Event Tracking: Check if this is a new event or an extension
                    const active = activeEvents.get(normalizedRut);
                    if (!active) {
                        // NEW EVENT START detected by presence
                        activeEvents.set(normalizedRut, {
                            startDate: p.admissionDate || date,
                            lastSeen: date,
                            bedId,
                            diagnosis: p.pathology || 'Ingreso detected by presence'
                        });

                        master.hospitalizations?.push({
                            id: `${date}-ingreso-auto`,
                            type: 'Ingreso',
                            date: p.admissionDate || date,
                            diagnosis: p.pathology || 'Ingreso detectado',
                            bedName: bedId
                        });
                        master.lastAdmission = p.admissionDate || date;
                    } else {
                        // Update last seen for existing event
                        active.lastSeen = date;
                    }
                }

                // 2. Process explicit discharges/transfers
                const dischargesToday = record.discharges || [];
                const transfersToday = record.transfers || [];

                for (const d of dischargesToday) {
                    if (!d.rut || !isValidRut(d.rut)) continue;
                    const normalizedRut = formatRut(d.rut).toUpperCase();
                    const master = patientsMap.get(normalizedRut);
                    if (master) {
                        master.hospitalizations?.push({
                            id: `${date}-egreso`,
                            type: 'Egreso',
                            date: date,
                            diagnosis: d.diagnosis || 'S/D',
                            bedName: d.bedName
                        });
                        master.lastDischarge = date;
                        if (d.status === 'Fallecido') {
                            master.vitalStatus = 'Fallecido';
                            master.hospitalizations?.push({
                                id: `${date}-defuncion`,
                                type: 'Fallecimiento',
                                date: date,
                                diagnosis: d.diagnosis
                            });
                        }
                        // Explicitly end active event
                        activeEvents.delete(normalizedRut);
                    }
                }

                for (const t of transfersToday) {
                    if (!t.rut || !isValidRut(t.rut)) continue;
                    const normalizedRut = formatRut(t.rut).toUpperCase();
                    const master = patientsMap.get(normalizedRut);
                    if (master) {
                        master.hospitalizations?.push({
                            id: `${date}-traslado`,
                            type: 'Traslado',
                            date: date,
                            diagnosis: t.diagnosis || 'S/D',
                            bedName: t.bedName,
                            receivingCenter: t.receivingCenter
                        });
                        // Explicitly end active event
                        activeEvents.delete(normalizedRut);
                    }
                }

                // 3. Detect "Silent Discharges" (Gone from census today without explicit event)
                for (const [rut, active] of Array.from(activeEvents.entries())) {
                    if (!rutsInCensusToday.has(rut)) {
                        const master = patientsMap.get(rut);
                        if (master) {
                            master.hospitalizations?.push({
                                id: `${active.lastSeen}-egreso-auto`,
                                type: 'Egreso',
                                date: active.lastSeen,
                                diagnosis: active.diagnosis || 'Salida automática (no detectado en censo)',
                                bedName: active.bedId
                            });
                            master.lastDischarge = active.lastSeen;
                        }
                        activeEvents.delete(rut);
                    }
                }
            }

            setAnalysis({
                totalRecords: dates.length,
                uniquePatients: patientsMap.size,
                validPatients: Array.from(patientsMap.values()),
                conflicts: conflicts
            });

        } catch (error) {
            console.error("Analysis failed", error);
        } finally {
            setIsAnalyzing(false);
        }
    }, []);

    const runMigration = useCallback(async () => {
        if (!analysis || analysis.validPatients.length === 0) return;

        setIsMigrating(true);
        try {
            const { successes, errors } = await PatientMasterRepository.bulkUpsertPatients(analysis.validPatients);
            setMigrationResult({ successes, errors });
        } catch (error) {
            console.error("Migration failed", error);
        } finally {
            setIsMigrating(false);
        }
    }, [analysis]);

    return {
        isAnalyzing,
        isMigrating,
        isHarmonizing,
        analysis,
        migrationResult,
        runAnalysis,
        runMigration,
        resolveConflict
    };
};

import { useState, useCallback } from 'react';
import { TransferRequest, TransferFormData } from '@/types/transfers';
import { QuestionnaireResponse, TransferPatientData, GeneratedDocument } from '@/types/transferDocuments';
import { getHospitalConfigById } from '@/constants/hospitalConfigs';
import { generateTransferDocuments } from '@/services/transfers/documentGeneratorService';
import { DailyRecord } from '@/types';

export const useTransferViewStates = (
    record: DailyRecord | null,
    updateTransfer: (id: string, data: Partial<TransferRequest>) => Promise<void>,
    createTransfer: (data: TransferFormData) => Promise<void>,
    advanceStatus: (transfer: TransferRequest) => Promise<void>,
    markAsTransferred: (transfer: TransferRequest, method: string) => Promise<void>,
    cancelTransfer: (transfer: TransferRequest, reason: string) => Promise<void>
) => {
    const [isFormModalOpen, setIsFormModalOpen] = useState(false);
    const [isStatusModalOpen, setIsStatusModalOpen] = useState(false);
    const [isTransferModalOpen, setIsTransferModalOpen] = useState(false);
    const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);
    const [isQuestionnaireOpen, setIsQuestionnaireOpen] = useState(false);
    const [isPackageModalOpen, setIsPackageModalOpen] = useState(false);
    const [selectedTransfer, setSelectedTransfer] = useState<TransferRequest | null>(null);
    const [selectedHospitalId, setSelectedHospitalId] = useState<string>('hospital-salvador');
    const [isGenerating, setIsGenerating] = useState(false);
    const [generatedDocs, setGeneratedDocs] = useState<GeneratedDocument[]>([]);
    const [patientDataForDocs, setPatientDataForDocs] = useState<TransferPatientData | null>(null);

    const handleNewRequest = useCallback(() => {
        setSelectedTransfer(null);
        setIsFormModalOpen(true);
    }, []);

    const handleEditTransfer = useCallback((transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsFormModalOpen(true);
    }, []);

    const handleCloseFormModal = useCallback(() => {
        setIsFormModalOpen(false);
        setSelectedTransfer(null);
    }, []);

    const handleSave = async (data: TransferFormData) => {
        if (selectedTransfer) {
            await updateTransfer(selectedTransfer.id, data);
        } else {
            await createTransfer(data);
        }
        handleCloseFormModal();
    };

    const handleStatusChange = useCallback((transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsStatusModalOpen(true);
    }, []);

    const handleCloseStatusModal = useCallback(() => {
        setIsStatusModalOpen(false);
        setSelectedTransfer(null);
    }, []);

    const handleConfirmStatusChange = async (_notes?: string) => {
        if (selectedTransfer) {
            await advanceStatus(selectedTransfer);
        }
    };

    const handleMarkTransferred = useCallback((transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsTransferModalOpen(true);
    }, []);

    const handleCloseTransferModal = useCallback(() => {
        setIsTransferModalOpen(false);
        setSelectedTransfer(null);
    }, []);

    const handleConfirmTransfer = async (transferMethod: string) => {
        if (selectedTransfer) {
            await markAsTransferred(selectedTransfer, transferMethod);
        }
    };

    const handleCancel = useCallback((transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setIsCancelModalOpen(true);
    }, []);

    const handleCloseCancelModal = useCallback(() => {
        setIsCancelModalOpen(false);
        setSelectedTransfer(null);
    }, []);

    const handleConfirmCancel = async (reason: string) => {
        if (selectedTransfer) {
            await cancelTransfer(selectedTransfer, reason);
        }
    };

    const handleGenerateDocs = useCallback((transfer: TransferRequest) => {
        setSelectedTransfer(transfer);
        setSelectedHospitalId('hospital-salvador');
        setIsQuestionnaireOpen(true);
    }, []);

    const handleCloseQuestionnaire = useCallback(() => {
        setIsQuestionnaireOpen(false);
        setSelectedTransfer(null);
    }, []);

    const handleQuestionnaireComplete = useCallback(async (responses: QuestionnaireResponse) => {
        if (!selectedTransfer || !selectedHospitalId) return;

        const hospital = getHospitalConfigById(selectedHospitalId);
        if (!hospital) return;

        setIsGenerating(true);
        try {
            await updateTransfer(selectedTransfer.id, {
                questionnaireResponses: responses
            });

            const snapshot = selectedTransfer.patientSnapshot as unknown as any;
            const currentPatient = record?.beds[selectedTransfer.bedId];
            const birthDate = snapshot.birthDate || currentPatient?.birthDate || '';

            const patientData: TransferPatientData = {
                patientName: selectedTransfer.patientSnapshot.name,
                rut: selectedTransfer.patientSnapshot.rut || '',
                birthDate: birthDate,
                age: selectedTransfer.patientSnapshot.age,
                diagnosis: selectedTransfer.patientSnapshot.diagnosis,
                admissionDate: selectedTransfer.patientSnapshot.admissionDate,
                bedName: selectedTransfer.bedId.replace('BED_', ''),
                bedType: 'Básica',
                isUPC: false,
                originHospital: 'Hospital Hanga Roa'
            };

            const documents = await generateTransferDocuments(patientData, responses, hospital);
            setGeneratedDocs(documents);
            setPatientDataForDocs(patientData);
            setIsQuestionnaireOpen(false);
            setIsPackageModalOpen(true);
        } catch (error) {
            console.error('Error generating documents:', error);
            alert('Error al generar documentos. Por favor intente nuevamente.');
        } finally {
            setIsGenerating(false);
        }
    }, [selectedTransfer, selectedHospitalId, updateTransfer, record]);

    const handleViewDocs = useCallback(async (transfer: TransferRequest) => {
        if (!transfer.questionnaireResponses) return;
        setSelectedTransfer(transfer);
        setSelectedHospitalId('hospital-salvador');
        await handleQuestionnaireComplete(transfer.questionnaireResponses);
    }, [handleQuestionnaireComplete]);

    const handleClosePackageModal = useCallback(() => {
        setIsPackageModalOpen(false);
        setSelectedTransfer(null);
        setGeneratedDocs([]);
    }, []);

    return {
        modals: {
            form: isFormModalOpen,
            status: isStatusModalOpen,
            transfer: isTransferModalOpen,
            cancel: isCancelModalOpen,
            questionnaire: isQuestionnaireOpen,
            package: isPackageModalOpen
        },
        selectedTransfer,
        selectedHospitalId,
        isGenerating,
        generatedDocs,
        patientDataForDocs,
        handlers: {
            handleNewRequest,
            handleEditTransfer,
            handleCloseFormModal,
            handleSave,
            handleStatusChange,
            handleCloseStatusModal,
            handleConfirmStatusChange,
            handleMarkTransferred,
            handleCloseTransferModal,
            handleConfirmTransfer,
            handleCancel,
            handleCloseCancelModal,
            handleConfirmCancel,
            handleGenerateDocs,
            handleCloseQuestionnaire,
            handleQuestionnaireComplete,
            handleViewDocs,
            handleClosePackageModal
        }
    };
};

/**
 * Advanced Service Worker for HHR Hospital Tracker
 * This file is processed by VitePWA using the 'injectManifest' strategy.
 */

import { precacheAndRoute, cleanupOutdatedCaches } from 'workbox-precaching';
import { registerRoute, setCatchHandler } from 'workbox-routing';
import { StaleWhileRevalidate, CacheFirst, NetworkFirst, NetworkOnly } from 'workbox-strategies';
import { ExpirationPlugin } from 'workbox-expiration';
import { CacheableResponsePlugin } from 'workbox-cacheable-response';
import { BackgroundSyncPlugin } from 'workbox-background-sync';

// Define proper types for Service Worker variables and events
interface WBManifestEntry {
    url: string;
    revision: string | null;
}

interface ExtendableEvent extends Event {
    waitUntil(fn: Promise<any>): void;
}

interface FetchEvent extends ExtendableEvent {
    request: Request;
    respondWith(response: Promise<Response> | Response): void;
    preloadResponse: Promise<any>;
}

interface ExtendableMessageEvent extends ExtendableEvent {
    data: any;
    source: Client | ServiceWorker | MessagePort | null;
    ports: readonly MessagePort[];
}

interface Client {
    url: string;
    type: ClientType;
    id: string;
    postMessage(message: any, transfer?: Transferable[]): void;
}

type ClientType = "window" | "worker" | "sharedworker" | "all";

interface Clients {
    get(id: string): Promise<Client | undefined>;
    matchAll(options?: ClientMatchAllOptions): Promise<Client[]>;
    openWindow(url: string): Promise<Client | null>;
    claim(): Promise<void>;
}

interface ClientMatchAllOptions {
    includeUncontrolled?: boolean;
    type?: ClientType;
}

interface ServiceWorkerGlobalScope extends EventTarget {
    readonly clients: Clients;
    skipWaiting(): void;
}

// Use a typed constant for self to avoid redeclaration conflicts
const sw = self as unknown as ServiceWorkerGlobalScope & { __WB_MANIFEST: Array<WBManifestEntry> };

// ============================================
// PRECHACING & CLEANUP
// ============================================

// VitePWA will inject the manifest here - MUST use self.__WB_MANIFEST literal
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const manifest = (self as any).__WB_MANIFEST;

if (Array.isArray(manifest) && manifest.length > 0) {
    precacheAndRoute(manifest);
} else {
    console.warn('[SW] precacheAndRoute skipped: manifest is empty or not an array');
}

cleanupOutdatedCaches();

const CACHE_VERSION = 'v2.2.0';
const OFFLINE_PAGE = '/offline.html';

// ============================================
// CACHING STRATEGIES
// ============================================

// Static assets (JS, CSS) - Stale While Revalidate
registerRoute(
    ({ request }) => request.destination === 'script' || request.destination === 'style',
    new StaleWhileRevalidate({
        cacheName: `static-${CACHE_VERSION}`,
        plugins: [
            new CacheableResponsePlugin({ statuses: [0, 200] }),
            new ExpirationPlugin({ maxEntries: 60, maxAgeSeconds: 24 * 60 * 60 }),
        ],
    })
);

// Google Fonts - Cache First
registerRoute(
    ({ url }) => url.origin === 'https://fonts.googleapis.com' || url.origin === 'https://fonts.gstatic.com',
    new CacheFirst({
        cacheName: `fonts-${CACHE_VERSION}`,
        plugins: [
            new CacheableResponsePlugin({ statuses: [0, 200] }),
            new ExpirationPlugin({ maxEntries: 30, maxAgeSeconds: 365 * 24 * 60 * 60 }),
        ],
    })
);

// Images - Cache First
registerRoute(
    ({ request }) => request.destination === 'image',
    new CacheFirst({
        cacheName: `images-${CACHE_VERSION}`,
        plugins: [
            new CacheableResponsePlugin({ statuses: [0, 200] }),
            new ExpirationPlugin({ maxEntries: 100, maxAgeSeconds: 30 * 24 * 60 * 60 }),
        ],
    })
);

// Firebase/Firestore - Network First with cache fallback
registerRoute(
    ({ url }) => url.origin.includes('firebaseio.com') || url.origin.includes('googleapis.com'),
    new NetworkFirst({
        cacheName: `firebase-${CACHE_VERSION}`,
        networkTimeoutSeconds: 10,
        plugins: [
            new CacheableResponsePlugin({ statuses: [0, 200] }),
            new ExpirationPlugin({ maxEntries: 50, maxAgeSeconds: 60 * 60 }),
        ],
    })
);

// API calls with background sync for POST
let bgSyncPlugin: BackgroundSyncPlugin | undefined;
try {
    bgSyncPlugin = new BackgroundSyncPlugin('patientSyncQueue', {
        maxRetentionTime: 24 * 60, // Retry for up to 24 hours
    });
} catch (error) {
    console.error('[SW] Failed to initialize BackgroundSyncPlugin:', error);
}

registerRoute(
    ({ url, request }) => url.pathname.startsWith('/api/') && request.method === 'POST',
    new NetworkOnly({
        plugins: bgSyncPlugin ? [bgSyncPlugin] : [],
    }),
    'POST'
);

// Pages/Navigation - Network First
registerRoute(
    ({ request }) => request.mode === 'navigate',
    new NetworkFirst({
        cacheName: `pages-${CACHE_VERSION}`,
        networkTimeoutSeconds: 5,
        plugins: [
            new CacheableResponsePlugin({ statuses: [0, 200] }),
            new ExpirationPlugin({ maxEntries: 50 }),
        ],
    })
);

// Fallback for navigation failures
setCatchHandler(async ({ event }) => {
    const fetchEvent = event as FetchEvent;
    if (fetchEvent.request.mode === 'navigate') {
        const cache = await caches.open(`offline-${CACHE_VERSION}`);
        return (await cache.match(OFFLINE_PAGE)) || Response.error();
    }
    return Response.error();
});

// ============================================
// EVENT LISTENERS
// ============================================

sw.addEventListener('install', (event: Event) => {
    const extendableEvent = event as ExtendableEvent;
    extendableEvent.waitUntil(
        caches.open(`offline-${CACHE_VERSION}`).then((cache) => cache.add(OFFLINE_PAGE))
    );
    sw.skipWaiting();
});

sw.addEventListener('activate', (event: Event) => {
    const extendableEvent = event as ExtendableEvent;
    extendableEvent.waitUntil(sw.clients.claim());
});

sw.addEventListener('message', (event: Event) => {
    const messageEvent = event as ExtendableMessageEvent;
    if (messageEvent.data && messageEvent.data.type === 'SKIP_WAITING') {
        sw.skipWaiting();
    }
});

/**
 * Audit Utilities
 * Handles user identification and IP address tracking for audit logs.
 */

import { getAuth } from 'firebase/auth';
import { Timestamp } from 'firebase/firestore';

// ============================================================================
// User Identification
// ============================================================================

const USER_EMAIL_CACHE_KEY = 'hhr_audit_user_email_cache';

/**
 * Get current user email with robust fallbacks
 * Priority: auth.email → cached email → displayName → uid → anonymous
 */
export const getCurrentUserEmail = (): string => {
    try {
        const auth = getAuth();
        const user = auth.currentUser;

        if (user?.email) {
            localStorage.setItem(USER_EMAIL_CACHE_KEY, user.email);
            return user.email;
        }

        const cached = localStorage.getItem(USER_EMAIL_CACHE_KEY);
        if (cached) return cached;

        if (user?.displayName) return user.displayName;
        if (user?.uid) return user.uid;

        return 'anonymous_user';
    } catch (e) {
        console.warn('[Audit] Error getting user info:', e);
        return 'system_context';
    }
};

/**
 * Universal parser for audit timestamps
 * Handles ISO strings, Firebase Timestamps (objects or plain), 
 * numbers (ms), and Date objects.
 */
export const parseAuditTimestamp = (timestamp: unknown): Date => {
    if (!timestamp) return new Date(0);

    // Handle Firebase Timestamp objects (Firestore native)
    if (timestamp instanceof Timestamp) {
        return timestamp.toDate();
    }

    // Handle plain objects from JSON or duck-typed Timestamps
    if (typeof timestamp === 'object' && timestamp !== null) {
        // Duck typing for toDate()
        if ('toDate' in timestamp && typeof (timestamp as any).toDate === 'function') {
            return (timestamp as any).toDate();
        }

        // Handle plain objects with seconds/nanoseconds (common in serialized state)
        if ('seconds' in timestamp && typeof (timestamp as any).seconds === 'number') {
            return new Date((timestamp as any).seconds * 1000);
        }

        // Handle Date objects
        if (timestamp instanceof Date) {
            return timestamp;
        }
    }

    // Handle ISO strings or numbers (ms)
    if (typeof timestamp === 'string' || typeof timestamp === 'number') {
        const date = new Date(timestamp);
        return isNaN(date.getTime()) ? new Date(0) : date;
    }

    return new Date(0);
};

/**
 * Get user display name if available
 */
export const getCurrentUserDisplayName = (): string | undefined => {
    try {
        return getAuth().currentUser?.displayName || undefined;
    } catch (_e) {
        return undefined;
    }
};

/**
 * Get Firebase UID
 */
export const getCurrentUserUid = (): string | undefined => {
    try {
        return getAuth().currentUser?.uid || undefined;
    } catch (_e) {
        return undefined;
    }
};

// ============================================================================
// IP Address Tracking
// ============================================================================

const IP_CACHE_KEY = 'hhr_audit_user_ip';
let ipFetchInProgress = false;

/**
 * Get user's IP address (cached in session)
 * Non-blocking - returns cached value or undefined
 */
export const getCachedIpAddress = (): string | undefined => {
    return sessionStorage.getItem(IP_CACHE_KEY) || undefined;
};

/**
 * Fetch and cache user's IP address (call once at login)
 */
export const fetchAndCacheIpAddress = async (): Promise<string | undefined> => {
    if (ipFetchInProgress) return undefined;

    const cached = getCachedIpAddress();
    if (cached) return cached;

    ipFetchInProgress = true;
    try {
        const response = await fetch('https://api.ipify.org?format=json');
        const data = await response.json();
        if (data.ip) {
            sessionStorage.setItem(IP_CACHE_KEY, data.ip);
            return data.ip;
        }
    } catch (e) {
        console.warn('[Audit] Failed to fetch IP:', e);
    } finally {
        ipFetchInProgress = false;
    }
    return undefined;
};

/**
 * Census Storage Service
 * Handles uploading and managing Census Excel files in Firebase Storage
 */

import {
    ref,
    uploadBytes,
    getDownloadURL,
    deleteObject,
    getMetadata
} from 'firebase/storage';
import { storage, auth, firebaseReady } from '@/firebaseConfig';
import {
    createListYears,
    createListMonths,
    createListFilesInMonth,
    BaseStoredFile
} from './baseStorageService';

// ============= Types =============

export interface StoredCensusFile extends BaseStoredFile {
    // Census files don't have shiftType, just the base properties
}

// ============= Constants =============

const STORAGE_ROOT = 'censo-diario';

// ============= Helper Functions =============

/**
 * Generate file path for a Census Excel
 */
const generateCensusPath = (date: string): string => {
    const [year, month, day] = date.split('-'); // input date is YYYY-MM-DD
    const formattedDate = `${day}-${month}-${year}`;
    const filename = `${formattedDate} - Censo Diario.xlsx`;
    return `${STORAGE_ROOT}/${year}/${month}/${filename}`;
};

/**
 * Parse file path to extract date
 */
const parseFilePath = (path: string): { date: string } | null => {
    // Check if path ends with "DD-MM-YYYY - Censo Diario.xlsx"
    const match = path.match(/(\d{2})-(\d{2})-(\d{4}) - Censo Diario\.xlsx$/);
    if (match) {
        return {
            date: `${match[3]}-${match[2]}-${match[1]}` // Convert back to YYYY-MM-DD
        };
    }
    return null;
};

// ============= Core Functions =============

/**
 * Upload a Census Excel to Firebase Storage
 */
export const uploadCensus = async (
    excelBlob: Blob,
    date: string
): Promise<string> => {
    // console.info(`[CensusStorage] Starting upload for ${date}...`);
    await firebaseReady;

    const filePath = generateCensusPath(date);
    const storageRef = ref(storage, filePath);

    const user = auth.currentUser;
    const metadata = {
        contentType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        customMetadata: {
            date,
            uploadedBy: user?.email || 'unknown',
            uploadedAt: new Date().toISOString()
        }
    };

    await uploadBytes(storageRef, excelBlob, metadata);
    const downloadUrl = await getDownloadURL(storageRef);

    // console.info(`✅ [CensusStorage] Upload complete: ${filePath}`);
    return downloadUrl;
};

/**
 * Check if a Census file exists for a given date
 */
export const checkCensusExists = async (date: string): Promise<boolean> => {
    try {
        await firebaseReady;
        const filePath = generateCensusPath(date);
        const storageRef = ref(storage, filePath);
        await getMetadata(storageRef);
        return true;
    } catch (error: unknown) {
        // If file doesn't exist, getMetadata throws
        const storageError = error as { code?: string };
        if (storageError.code === 'storage/object-not-found') {
            return false;
        }
        console.warn('[CensusStorage] Error checking file existence:', error);
        return false;
    }
};

/**
 * Delete a Census file from Storage
 */
export const deleteCensusFile = async (date: string): Promise<void> => {
    const filePath = generateCensusPath(date);
    const storageRef = ref(storage, filePath);
    await deleteObject(storageRef);
    // console.info(`🗑️ Census deleted: ${filePath}`);
};

/**
 * List all years with Census files (using base service)
 */
export const listCensusYears = createListYears(STORAGE_ROOT);

/**
 * List all months in a year for Census (using base service)
 */
export const listCensusMonths = createListMonths(STORAGE_ROOT);

/**
 * List all Census files in a month (using base service)
 * Note: Display name is normalized to format (DD-MM-YYYY - Censo Diario.xlsx)
 */
export const listCensusFilesInMonth = createListFilesInMonth<StoredCensusFile>({
    storageRoot: STORAGE_ROOT,
    parseFilePath,
    mapToFile: (item, metadata, downloadUrl, parsed) => {
        // Generate normalized display name from parsed date
        const [year, month, day] = parsed.date.split('-');
        const displayName = `${day}-${month}-${year} - Censo Diario.xlsx`;

        return {
            name: displayName, // Always use normalized format for display
            fullPath: item.fullPath,
            downloadUrl,
            date: parsed.date,
            createdAt: metadata.customMetadata?.uploadedAt || metadata.timeCreated,
            size: metadata.size
        };
    }
});

/**
 * IndexedDB Service using Dexie.js
 * 
 * Provides persistent storage with unlimited capacity (vs 5MB localStorage limit).
 * Includes automatic migration from localStorage to IndexedDB.
 */

import Dexie, { Table } from 'dexie';
import { DailyRecord } from '@/types';
import { ErrorLog } from '@/services/utils/errorService';
import { AuditLogEntry } from '@/types/audit';

import { SyncTask } from './syncQueueService';

// ============================================================================
// Database Schema
// ============================================================================

export class HangaRoaDatabase extends Dexie {
    dailyRecords!: Table<DailyRecord>;
    demoRecords!: Table<DailyRecord>;
    catalogs!: Table<{ id: string, list: string[], lastUpdated: string }>;
    errorLogs!: Table<ErrorLog>;
    auditLogs!: Table<AuditLogEntry>;
    settings!: Table<{ id: string, value: unknown }>;
    syncQueue!: Table<SyncTask>;

    constructor() {
        super('HangaRoaDB');

        this.version(6).stores({
            dailyRecords: 'date',
            demoRecords: 'date',
            catalogs: 'id',
            errorLogs: 'id, timestamp, severity',
            auditLogs: 'id, timestamp, action, entityId, recordDate',
            settings: 'id',
            syncQueue: '++id, status, timestamp'
        });
    }
}

/**
 * Mock fallback for HangaRoaDatabase when initialization fails.
 */
export const createMockDatabase = (): HangaRoaDatabase => {
    const mockTable = {
        toArray: () => Promise.resolve([]),
        get: () => Promise.resolve(null),
        put: () => Promise.resolve(''),
        delete: () => Promise.resolve(),
        clear: () => Promise.resolve(),
        bulkPut: () => Promise.resolve(''),
        add: () => Promise.resolve(''),
        orderBy: () => ({
            reverse: () => ({
                limit: () => ({ toArray: () => Promise.resolve([]) }),
                keys: () => Promise.resolve([]),
                toArray: () => Promise.resolve([])
            })
        }),
        where: (_key: string) => ({
            below: () => ({
                reverse: () => ({
                    first: () => Promise.resolve(null)
                })
            }),
            equals: () => ({
                first: () => Promise.resolve(null),
                toArray: () => Promise.resolve([])
            }),
            startsWith: () => ({
                toArray: () => Promise.resolve([])
            })
        })
    } as unknown;

    return {
        dailyRecords: mockTable,
        demoRecords: mockTable,
        catalogs: mockTable,
        auditLogs: mockTable,
        settings: mockTable,
        isOpen: () => true,
        open: () => Promise.resolve(),
        on: () => ({})
    } as unknown as HangaRoaDatabase;
};

// Singleton instance with safety
let db: HangaRoaDatabase;
let isUsingMock = false;

try {
    db = new HangaRoaDatabase();

    // Handle blocking (multiple tabs trying to upgrade)
    db.on('blocked', () => {
        console.warn('[IndexedDB] ⏳ Database is blocked by another tab');
    });

    // Handle sudden closure or version changes
    db.on('close', () => {
        console.warn('[IndexedDB] 🚪 Database connection closed unexpectedly.');
    });

} catch (e) {
    console.error('[IndexedDB] ❌ Failed to construct HangaRoaDatabase:', e);
    db = createMockDatabase();
    isUsingMock = true;
    console.error('[IndexedDB] !!! USING MOCK DATABASE !!! Data will be lost on reload.');
}

let isOpening = false;

/**
 * Ensures the database is open or falls back to mock.
 * Includes automatic recovery logic for Chrome's "UnknownError".
 */
const ensureDbReady = async () => {
    // 0. E2E Bypass: Don't hang on IndexedDB during VRT/Tests
    if (typeof window !== 'undefined' && (window as any).__HHR_E2E_OVERRIDE__) {
        isUsingMock = true;
        return;
    }

    if (isUsingMock) return;

    // Check if open. If open, verify connection isn't "closed" but not reporting it.
    if (db.isOpen()) {
        try {
            // Quick check to see if connection is healthy
            await db.settings.get('__health_check__');
            return;
        } catch (err: unknown) {
            if (err && typeof err === 'object' && (err as { name?: string }).name === 'DatabaseClosedError') {
                console.warn('[IndexedDB] 🔄 Detected DatabaseClosedError, attempting to re-open...');
                // Fall through to open logic
            } else {
                return;
            }
        }
    }

    if (isOpening) {
        while (isOpening) {
            await new Promise(resolve => setTimeout(resolve, 100));
            if (db.isOpen() || isUsingMock) return;
        }
        return;
    }

    isOpening = true;
    try {
        console.warn('[IndexedDB] 📡 Opening database connection...');
        await db.open();
    } catch (err: unknown) {
        const errorName = err && typeof err === 'object' && 'name' in err ? String(err.name) : 'Unknown';
        const errorMessage = err && typeof err === 'object' && 'message' in err ? String(err.message) : String(err);

        console.warn('[IndexedDB] ⚠️ Initial open failed, attempting auto-recovery:', errorName || errorMessage);

        // If it's a known persistent error (like UnknownError or VersionError), 
        // try to delete and recreate the database once.
        if (errorName === 'UnknownError' || errorName === 'VersionError') {
            try {
                console.warn('[IndexedDB] 🛠️ Deleting corrupted database for recreation...');
                await db.close();
                await Dexie.delete('HangaRoaDB');

                // Re-instantiate and try again
                db = new HangaRoaDatabase();
                await db.open();

                // console.info('[IndexedDB] ✨ Database successfully recreated and opened');

                // Re-trigger migration since we started fresh
                localStorage.removeItem(MIGRATION_FLAG);
                migrateFromLocalStorage();

                isOpening = false;
                return;
            } catch (recoveryErr) {
                console.error('[IndexedDB] ❌ Recovery failed:', recoveryErr);
            }
        }

        console.error('[IndexedDB] 💨 Falling back to Memory Storage (Mock)');
        isUsingMock = true;
        const mock = createMockDatabase();
        db.dailyRecords = mock.dailyRecords;
        db.catalogs = mock.catalogs;
        db.errorLogs = mock.errorLogs;
        db.auditLogs = mock.auditLogs;
    } finally {
        isOpening = false;
    }
};

// ============================================================================
// Error Log Operations
// ============================================================================

export const saveErrorLog = async (log: ErrorLog): Promise<void> => {
    try {
        await ensureDbReady();
        await db.errorLogs.add(log);
    } catch (err) {
        console.warn('Failed to save error log to IndexedDB:', err);
    }
};

export const getErrorLogs = async (limit = 50): Promise<ErrorLog[]> => {
    try {
        await ensureDbReady();
        return await db.errorLogs
            .orderBy('timestamp')
            .reverse()
            .limit(limit)
            .toArray();
    } catch (err) {
        console.error('Failed to retrieve error logs:', err);
        return [];
    }
};

export const clearErrorLogs = async (): Promise<void> => {
    try {
        await ensureDbReady();
        await db.errorLogs.clear();
    } catch (err) {
        console.warn('Failed to clear error logs:', err);
    }
};

// ============================================================================
// Daily Records Operations
// ============================================================================

export const getAllRecords = async (): Promise<Record<string, DailyRecord>> => {
    try {
        await ensureDbReady();
        const records = await db.dailyRecords.toArray();
        const result: Record<string, DailyRecord> = {};
        for (const record of records) {
            result[record.date] = record;
        }
