import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { RutPassportInput } from '@/features/census/components/patient-row/RutPassportInput';
import { usePatientAutocomplete } from '@/hooks/usePatientAutocomplete';
import { vi, describe, it, expect, beforeEach } from 'vitest';

// Mock dependencies
vi.mock('@/hooks/usePatientAutocomplete');
vi.mock('@/components/ui/DebouncedInput', () => ({
    DebouncedInput: ({ value, onChange, placeholder }: any) => (
        <input
            data-testid="rut-input"
            value={value}
            onChange={(e) => onChange(e.target.value)}
            placeholder={placeholder}
        />
    )
}));

describe('RutPassportInput Toast Logic', () => {
    const mockOnChange = vi.fn();
    const mockOnAutofill = vi.fn();
    const today = new Date().toLocaleDateString('en-CA'); // strict system date

    const mockSuggestion = {
        rut: '12.345.678-9',
        fullName: 'Juan Perez',
        birthDate: '1990-01-01',
        gender: 'Masculino',
        forecast: 'Fonasa'
    };

    beforeEach(() => {
        vi.clearAllMocks();
        // Reset hook mock to default empty
        (usePatientAutocomplete as any).mockReturnValue({
            suggestion: null,
            isLoading: false
        });
    });

    it('should NOT show toast if date is not strictly today', async () => {
        (usePatientAutocomplete as any).mockReturnValue({
            suggestion: mockSuggestion,
            isLoading: false
        });

        // Current view date is YESTERDAY
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = yesterday.toLocaleDateString('en-CA');

        render(
            <RutPassportInput
                value="12.345.678-9"
                documentType="RUT"
                onChange={mockOnChange}
                currentDateString={yesterdayStr} // Not today
                admissionDate={yesterdayStr}
                patientName="" // Empty name triggers suggestion check
                onAutofill={mockOnAutofill}
            />
        );

        // Wait for potential debounce (circuit breaker ensures it stays hidden)
        await waitFor(() => { }, { timeout: 600 });

        expect(screen.queryByText('Paciente Identificado')).not.toBeInTheDocument();
    });

    it('should show toast if date IS strictly today and name mismatches', async () => {
        (usePatientAutocomplete as any).mockReturnValue({
            suggestion: mockSuggestion,
            isLoading: false
        });

        render(
            <RutPassportInput
                value="12.345.678-9"
                documentType="RUT"
                onChange={mockOnChange}
                currentDateString={today} // STRICTLY TODAY
                admissionDate={today}
                patientName="" // Empty name -> mismatch
                onAutofill={mockOnAutofill}
            />
        );

        // Wait for 500ms debounce
        await waitFor(() => {
            expect(screen.getByText('Paciente Identificado')).toBeInTheDocument();
        }, { timeout: 1000 });

        expect(screen.getByText('Juan Perez')).toBeInTheDocument();
    });

    it('should NOT show toast if dismissed via button', async () => {
        (usePatientAutocomplete as any).mockReturnValue({
            suggestion: mockSuggestion,
            isLoading: false
        });

        render(
            <RutPassportInput
                value="12.345.678-9"
                documentType="RUT"
                onChange={mockOnChange}
                currentDateString={today}
                admissionDate={today}
                patientName=""
                onAutofill={mockOnAutofill}
            />
        );

        // Wait for appearance
        await waitFor(() => {
            expect(screen.getByText('Paciente Identificado')).toBeInTheDocument();
        });

        // Click dismiss button
        const dismissBtn = screen.getByTitle('Descartar sugerencia por hoy');
        fireEvent.click(dismissBtn);

        // Should disappear
        expect(screen.queryByText('Paciente Identificado')).not.toBeInTheDocument();
    });

    it('should NOT show toast if names match (normalized)', async () => {
        (usePatientAutocomplete as any).mockReturnValue({
            suggestion: mockSuggestion, // Name: Juan Perez
