import React from 'react';
import { render, screen, act, fireEvent } from '@testing-library/react';
import { describe, it, expect, vi } from 'vitest';
import { UIProvider, useUI } from '@/context/UIContext';

// Helper component to test useUI
const TestComponent = () => {
    const { success, error, confirm, alert } = useUI();
    return (
        <div>
            <button onClick={() => success('Success Title', 'Success Message')}>Notify Success</button>
            <button onClick={() => error('Error Title', 'Error Message')}>Notify Error</button>
            <button onClick={() => confirm({ message: 'Confirm Message' })}>Trigger Confirm</button>
            <button onClick={() => alert('Alert Message')}>Trigger Alert</button>
        </div>
    );
};

describe('UIContext', () => {
    it('should show success notification', async () => {
        render(
            <UIProvider>
                <TestComponent />
            </UIProvider>
        );

        const button = screen.getByText('Notify Success');
        act(() => {
            fireEvent.click(button);
        });

        expect(screen.getByText('Success Title')).toBeInTheDocument();
        expect(screen.getByText('Success Message')).toBeInTheDocument();
    });

    it('should show error notification', () => {
        render(
            <UIProvider>
                <TestComponent />
            </UIProvider>
        );

        const button = screen.getByText('Notify Error');
        act(() => {
            fireEvent.click(button);
        });

        expect(screen.getByText('Error Title')).toBeInTheDocument();
    });

    it('should handle confirm dialog (confirm)', async () => {
        let result: boolean | null = null;
        const ConfirmRequester = () => {
            const { confirm } = useUI();
            return <button onClick={async () => { result = await confirm({ message: 'Are you sure?' }); }}>Confirm</button>;
        };

        render(
            <UIProvider>
                <ConfirmRequester />
            </UIProvider>
        );

        fireEvent.click(screen.getByText('Confirm'));

        expect(screen.getByText('Are you sure?')).toBeInTheDocument();

        const confirmBtn = screen.getByRole('button', { name: /Confirmar/i });
        await act(async () => {
            fireEvent.click(confirmBtn);
        });

        expect(result).toBe(true);
        expect(screen.queryByText('Are you sure?')).not.toBeInTheDocument();
    });

    it('should handle confirm dialog (cancel)', async () => {
        let result: boolean | null = null;
        const ConfirmRequester = () => {
            const { confirm } = useUI();
            return <button onClick={async () => { result = await confirm({ message: 'Proceed?' }); }}>Confirm</button>;
        };

        render(
            <UIProvider>
                <ConfirmRequester />
            </UIProvider>
        );

        fireEvent.click(screen.getByText('Confirm'));

        const cancelBtn = screen.getByRole('button', { name: /Cancelar/i });
        await act(async () => {
            fireEvent.click(cancelBtn);
        });

        expect(result).toBe(false);
    });

    it('should handle alert dialog', async () => {
        render(
            <UIProvider>
                <TestComponent />
            </UIProvider>
        );

        fireEvent.click(screen.getByText('Trigger Alert'));

        expect(screen.getByText('Alert Message')).toBeInTheDocument();

        const okBtn = screen.getByRole('button', { name: /Aceptar/i });
        await act(async () => {
            fireEvent.click(okBtn);
        });

        expect(screen.queryByText('Alert Message')).not.toBeInTheDocument();
    });
});

/**
 * Tests for Bed Operations - Simplified
 * Tests basic bed operation logic without complex hook dependencies.
 */

import { describe, it, expect, vi } from 'vitest';
import { PatientData, DailyRecord } from '@/types';

// Test helper functions directly instead of hooks
const createEmptyPatient = (bedId: string): PatientData => ({
    bedId,
    patientName: '',
    bedMode: 'Cama',
    hasCompanionCrib: false,
    isBlocked: false,
} as unknown as PatientData);

const createPatient = (name: string, bedId: string): PatientData => ({
    bedId,
    patientName: name,
    rut: '12345678-9',
    pathology: 'Test',
    age: '30',
    insurance: 'Fonasa',
    origin: 'Residente',
    isRapanui: false,
    bedMode: 'Cama',
    hasCompanionCrib: false,
    isBlocked: false,
} as unknown as PatientData);

describe('Bed Operations Logic', () => {
    describe('Blocked Beds Logic', () => {
        it('should correctly identify blocked bed', () => {
            const bed = createEmptyPatient('bed-1');
            bed.isBlocked = true;
            expect(bed.isBlocked).toBe(true);
        });

        it('should correctly identify unblocked bed', () => {
            const bed = createEmptyPatient('bed-1');
            expect(bed.isBlocked).toBe(false);
        });

        it('should toggle blocked status', () => {
            const bed = createEmptyPatient('bed-1');
            bed.isBlocked = !bed.isBlocked;
            expect(bed.isBlocked).toBe(true);
            bed.isBlocked = !bed.isBlocked;
            expect(bed.isBlocked).toBe(false);
        });
    });

    describe('Clinical Crib Logic', () => {
        it('should add clinical crib to patient', () => {
            const patient = createPatient('Madre', 'bed-1');
            patient.clinicalCrib = {
                patientName: 'Recién Nacido',
                rut: '11111111-1',
            } as any;

            expect(patient.clinicalCrib?.patientName).toBe('Recién Nacido');
        });

        it('should check if clinical crib exists', () => {
            const patient = createPatient('Madre', 'bed-1');
            expect(patient.clinicalCrib).toBeUndefined();

            patient.clinicalCrib = { patientName: 'RN' } as any;
            expect(patient.clinicalCrib).toBeDefined();
        });

        it('should clear clinical crib', () => {
            const patient = createPatient('Madre', 'bed-1');
            patient.clinicalCrib = { patientName: 'RN' } as any;
            patient.clinicalCrib = undefined;
            expect(patient.clinicalCrib).toBeUndefined();
        });
    });

    describe('Patient Clear Logic', () => {
        it('should clear patient name', () => {
            const patient = createPatient('Juan', 'bed-1');
            expect(patient.patientName).toBe('Juan');

            patient.patientName = '';
            expect(patient.patientName).toBe('');
        });

        it('should check if bed is empty', () => {
            const emptyBed = createEmptyPatient('bed-1');
            const occupiedBed = createPatient('Juan', 'bed-2');

            expect(emptyBed.patientName).toBe('');
            expect(Boolean(emptyBed.patientName)).toBe(false);
            expect(Boolean(occupiedBed.patientName)).toBe(true);
        });
    });

    describe('Bed Mode Logic', () => {
        it('should toggle bed mode', () => {
            const bed = createEmptyPatient('bed-1');
            expect(bed.bedMode).toBe('Cama');

            bed.bedMode = 'Cuna';
            expect(bed.bedMode).toBe('Cuna');
        });

        it('should check companion crib status', () => {
            const bed = createPatient('Maria', 'bed-1');
            expect(bed.hasCompanionCrib).toBe(false);

            bed.hasCompanionCrib = true;
            expect(bed.hasCompanionCrib).toBe(true);
        });
    });
});

/**
 * Tests for Copy Previous Day Functionality
 * Verifies that copying from previous day works correctly.
 */

import { describe, it, expect, vi } from 'vitest';
import { DailyRecord, PatientData, Specialty, PatientStatus, CudyrScore } from '@/types';

// Simulate the copy logic from DailyRecordRepository
const copyPatientsFromPrevious = (
    prevRecord: DailyRecord,
    newDate: string
): Partial<DailyRecord> => {
    const newBeds: Record<string, PatientData> = {};

    Object.keys(prevRecord.beds).forEach(bedId => {
        const prevPatient = prevRecord.beds[bedId];

        if (prevPatient.patientName || prevPatient.isBlocked) {
            // Deep copy patient
            const copiedPatient = JSON.parse(JSON.stringify(prevPatient));
            newBeds[bedId] = {
                ...copiedPatient,
                // Reset CUDYR for new day
                cudyr: undefined,
            };
        } else {
            // Empty bed
            newBeds[bedId] = {
                bedId,
                patientName: '',
                rut: '',
                age: '',
                admissionDate: '',
                pathology: '',
                specialty: Specialty.EMPTY,
                status: PatientStatus.EMPTY,
                hasWristband: false,
                devices: [],
                surgicalComplication: false,
                isUPC: false,
                bedMode: prevPatient.bedMode || 'Cama',
                hasCompanionCrib: prevPatient.hasCompanionCrib || false,
                isBlocked: false,
            };
        }
    });

    return {
        date: newDate,
        beds: newBeds,
        discharges: [], // New day starts with no discharges
        transfers: [], // New day starts with no transfers
        cma: [], // New day starts with no CMA
        activeExtraBeds: [...(prevRecord.activeExtraBeds || [])],
    };
};

describe('Copy Previous Day', () => {
    const createPatient = (name: string, bedId: string): PatientData => ({
        bedId,
        patientName: name,
        rut: '12345678-9',
        pathology: 'Test Pathology',
        age: '40',
        insurance: 'Fonasa',
        origin: 'Residente',
        isRapanui: true,
        bedMode: 'Cama',
        hasCompanionCrib: false,
        isBlocked: false,
        admissionDate: '2024-01-01',
        specialty: Specialty.MEDICINA,
        status: PatientStatus.ESTABLE,
        hasWristband: true,
        devices: [],
        surgicalComplication: false,
        isUPC: false,
        cudyr: {
            changeClothes: 1,
            mobilization: 1,
            feeding: 1,
            elimination: 1,
            psychosocial: 1,
            surveillance: 1,
            vitalSigns: 1,
            fluidBalance: 1,
            oxygenTherapy: 1,
            airway: 1,
            proInterventions: 1,
            skinCare: 1,
            pharmacology: 1,
            invasiveElements: 1
        },
    });

    const createEmptyBed = (bedId: string): PatientData => ({
        bedId,
        patientName: '',
        rut: '',
        age: '',
        admissionDate: '',
        pathology: '',
        specialty: Specialty.EMPTY,
        status: PatientStatus.EMPTY,
        hasWristband: false,
        devices: [],
        surgicalComplication: false,
        isUPC: false,
        bedMode: 'Cama',
        hasCompanionCrib: false,
        isBlocked: false,
    });

    describe('Patient Copying', () => {
        it('should copy occupied beds to new day', () => {
            const prevRecord: DailyRecord = {
                date: '2024-12-22',
                beds: {
                    'bed-1': createPatient('Juan', 'bed-1'),
                    'bed-2': createPatient('María', 'bed-2'),
                    'bed-3': createEmptyBed('bed-3'),
                },
                discharges: [],
                transfers: [],
                cma: [],
                lastUpdated: '',
                nurses: [],
                activeExtraBeds: [],
            };

            const newDay = copyPatientsFromPrevious(prevRecord, '2024-12-23');

            expect(newDay.beds?.['bed-1'].patientName).toBe('Juan');
            expect(newDay.beds?.['bed-2'].patientName).toBe('María');
            expect(newDay.beds?.['bed-3'].patientName).toBe('');
        });

        it('should reset CUDYR scores for new day', () => {
            const prevRecord: DailyRecord = {
                date: '2024-12-22',
                beds: {
                    'bed-1': createPatient('Juan', 'bed-1'),
                },
                discharges: [],
                transfers: [],
                cma: [],
                lastUpdated: '',
                nurses: [],
                activeExtraBeds: [],
            };

            const newDay = copyPatientsFromPrevious(prevRecord, '2024-12-23');

            expect(newDay.beds?.['bed-1'].cudyr).toBeUndefined();
        });

        it('should copy blocked beds status', () => {
            const prevRecord: DailyRecord = {
                date: '2024-12-22',
                beds: {
                    'bed-1': { ...createEmptyBed('bed-1'), isBlocked: true },
                },
                discharges: [],
                transfers: [],
                cma: [],
                lastUpdated: '',
                nurses: [],
                activeExtraBeds: [],
            };

            const newDay = copyPatientsFromPrevious(prevRecord, '2024-12-23');

            // Blocked beds should be copied
            expect(newDay.beds?.['bed-1'].isBlocked).toBe(true);
        });

        it('should preserve bed mode (Cama/Cuna)', () => {
            const prevRecord: DailyRecord = {
                date: '2024-12-22',
