                date: '2024-12-22',
                beds: {},
                discharges: [],
                transfers: [{ id: 'old', patientName: 'Old' } as any],
                cma: [],
                lastUpdated: '',
                nurses: [],
                activeExtraBeds: [],
            };

            const newDay = copyPatientsFromPrevious(prevRecord, '2024-12-23');

            expect(newDay.transfers?.length).toBe(0);
