                hasWristband: true
            }
        },
        discharges: [],
        transfers: [],
        cma: [],
        lastUpdated: '',
        nurses: [],
        nursesDayShift: [],
        nursesNightShift: [],
        tensDayShift: [],
        tensNightShift: [],
        activeExtraBeds: []
    };

    beforeEach(() => {
        vi.clearAllMocks();
        vi.mocked(dateUtils.getShiftSchedule).mockReturnValue({ dayStart: '08:00', dayEnd: '20:00', nightStart: '20:00', nightEnd: '08:00', description: '' });
