        const mockUpdate = vi.fn();
        vi.mocked(useDailyRecordActions).mockReturnValue({
            updatePatient: mockUpdate,
            updatePatientMultiple: vi.fn(),
            updateClinicalCrib: vi.fn(),
            updateClinicalCribMultiple: vi.fn()
        } as any);

        const params = {
            type: 'nursing' as const,
            selectedShift: 'day' as const,
            setSelectedShift: vi.fn(),
            onSuccess: vi.fn(),
        };

        const { result } = renderHook(() => useHandoffLogic(params));

        await act(async () => {
            await result.current.handleClinicalEventAdd('R1', { name: 'Cirugía', date: '2025-01-01', note: '' });
        });

        expect(mockUpdate).toHaveBeenCalledWith('R1', 'clinicalEvents', expect.any(Array));
        expect(mockLogDebouncedEvent).toHaveBeenCalledWith('CLINICAL_EVENT_ADDED', 'patient', 'R1', expect.anything(), 'R1', '2025-01-01', undefined, 10000);

        // Delete
        const recordWithEvent = {
            ...mockRecord,
            beds: {
                R1: {
                    ...mockRecord.beds.R1,
                    clinicalEvents: [{ id: 'evt-1', name: 'Delete', date: '2025-01-01', note: '', createdAt: '' }]
                }
            }
        };

        // Update mock for the second part
        const mockUpdate2 = vi.fn();

        vi.mocked(useDailyRecordData).mockReturnValue({
            record: recordWithEvent as any,
            syncStatus: 'synced' as any,
            lastSyncTime: null,
            inventory: {} as any
        });
        vi.mocked(useDailyRecordActions).mockReturnValue({ updatePatient: mockUpdate2 } as any);

        const { result: res2 } = renderHook(() => useHandoffLogic(params));

        await act(async () => {
            await res2.current.handleClinicalEventDelete('R1', 'evt-1');
        });

        expect(mockUpdate2).toHaveBeenCalledWith('R1', 'clinicalEvents', []);
        expect(mockLogDebouncedEvent).toHaveBeenCalledWith('CLINICAL_EVENT_DELETED', 'patient', 'R1', expect.anything(), 'R1', '2025-01-01', undefined, 10000);
    });
});

import { renderHook } from '@testing-library/react';
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { useHandoffVisibility } from '@/hooks/useHandoffVisibility';
import { BEDS } from '@/constants';
import * as dateUtils from '@/utils/dateUtils';

vi.mock('../../utils/dateUtils', () => ({
    isAdmittedDuringShift: vi.fn()
}));

describe('useHandoffVisibility', () => {
    const mockRecord = {
        date: '2026-01-19',
        activeExtraBeds: ['E1'],
        beds: {
            'R1': { patientName: 'Patient 1', admissionDate: '2026-01-19', admissionTime: '10:00' },
            'R2': { isBlocked: true },
            'E1': { patientName: 'Extra Patient', admissionDate: '2026-01-19', admissionTime: '11:00' },
            'E2': { patientName: 'Extra Hidden', admissionDate: '2026-01-19', admissionTime: '12:00' }
        }
    } as any;

    beforeEach(() => {
        vi.clearAllMocks();
    });

    it('should return empty visibleBeds if record is null', () => {
        const { result } = renderHook(() => useHandoffVisibility(null, 'day'));
        expect(result.current.visibleBeds).toEqual([]);
        expect(result.current.hasAnyPatients).toBe(false);
    });

    it('should filter visibleBeds based on activeExtraBeds', () => {
        const { result } = renderHook(() => useHandoffVisibility(mockRecord, 'day'));

        const normalBeds = BEDS.filter(b => !b.isExtra);
        expect(result.current.visibleBeds.length).toBe(normalBeds.length + 1); // E1 is active
        expect(result.current.visibleBeds.find(b => b.id === 'E1')).toBeDefined();
        expect(result.current.visibleBeds.find(b => b.id === 'E2')).toBeUndefined();
    });

    it('should show patient based on isAdmittedDuringShift result', () => {
        vi.mocked(dateUtils.isAdmittedDuringShift).mockReturnValue(true);
        const { result } = renderHook(() => useHandoffVisibility(mockRecord, 'day'));

        expect(result.current.shouldShowPatient('R1')).toBe(true);
        expect(dateUtils.isAdmittedDuringShift).toHaveBeenCalledWith(
            '2026-01-19', '2026-01-19', '10:00', 'day'
        );
    });

    it('should always show blocked beds', () => {
        const { result } = renderHook(() => useHandoffVisibility(mockRecord, 'day'));
        vi.clearAllMocks(); // Clear calls from hasAnyPatients computation
        expect(result.current.shouldShowPatient('R2')).toBe(true);
        expect(dateUtils.isAdmittedDuringShift).not.toHaveBeenCalled();
    });

    it('should correctly calculate hasAnyPatients', () => {
        // Case 1: No patients visible in shift
        vi.mocked(dateUtils.isAdmittedDuringShift).mockReturnValue(false);
        const { result: res1 } = renderHook(() => useHandoffVisibility({ ...mockRecord, beds: { 'R1': mockRecord.beds.R1 } }, 'day'));
        expect(res1.current.hasAnyPatients).toBe(false);

        // Case 2: Blocked bed exists
        const { result: res2 } = renderHook(() => useHandoffVisibility(mockRecord, 'day'));
        expect(res2.current.hasAnyPatients).toBe(true); // Because R2 is blocked

        // Case 3: Patient visible in shift
        vi.mocked(dateUtils.isAdmittedDuringShift).mockReturnValue(true);
        const { result: res3 } = renderHook(() => useHandoffVisibility({ ...mockRecord, beds: { 'R1': mockRecord.beds.R1 } }, 'day'));
        expect(res3.current.hasAnyPatients).toBe(true);
    });
});

/**
 * Unit tests for useModal hook
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { useModal } from '@/hooks';

describe('useModal', () => {
    describe('initial state', () => {
        it('should start with isOpen false and data null', () => {
            const { result } = renderHook(() => useModal());

            expect(result.current.isOpen).toBe(false);
            expect(result.current.data).toBeNull();
        });
    });

    describe('open', () => {
        it('should set isOpen to true when open is called', () => {
            const { result } = renderHook(() => useModal());

            act(() => {
                result.current.open();
            });

            expect(result.current.isOpen).toBe(true);
        });

        it('should set data when open is called with initialData', () => {
            const { result } = renderHook(() => useModal<{ id: number }>());

            act(() => {
                result.current.open({ id: 123 });
            });

            expect(result.current.isOpen).toBe(true);
            expect(result.current.data).toEqual({ id: 123 });
        });
    });

    describe('close', () => {
        it('should set isOpen to false when close is called', () => {
            const { result } = renderHook(() => useModal());

            act(() => {
                result.current.open();
            });
            expect(result.current.isOpen).toBe(true);

            act(() => {
                result.current.close();
            });

            expect(result.current.isOpen).toBe(false);
        });

        it('should clear data after animation delay', async () => {
            vi.useFakeTimers();
            const { result } = renderHook(() => useModal<string>());

            act(() => {
                result.current.open('test data');
            });
            expect(result.current.data).toBe('test data');

            act(() => {
                result.current.close();
            });

            // Data should still exist immediately
            expect(result.current.isOpen).toBe(false);

            // Fast-forward past the animation delay
            act(() => {
                vi.advanceTimersByTime(300);
            });

            expect(result.current.data).toBeNull();

            vi.useRealTimers();
        });
    });

    describe('toggle', () => {
        it('should toggle isOpen state', () => {
            const { result } = renderHook(() => useModal());

            expect(result.current.isOpen).toBe(false);

            act(() => {
                result.current.toggle();
            });
            expect(result.current.isOpen).toBe(true);

            act(() => {
                result.current.toggle();
            });
            expect(result.current.isOpen).toBe(false);
        });
    });

    describe('type safety', () => {
        it('should work with complex data types', () => {
            interface Patient {
                id: string;
                name: string;
                age: number;
            }

            const { result } = renderHook(() => useModal<Patient>());

            const patient: Patient = { id: 'p1', name: 'John', age: 30 };

            act(() => {
                result.current.open(patient);
            });

            expect(result.current.data).toEqual(patient);
            expect(result.current.data?.name).toBe('John');
        });
    });
});

import { describe, it, expect, vi } from 'vitest';
import { renderHook } from '@testing-library/react';
import { usePatientValidation } from '@/hooks/usePatientValidation';

describe('usePatientValidation', () => {
    describe('formatPatientName', () => {
        it('should capitalize each word and trim whitespace', () => {
            const { result } = renderHook(() => usePatientValidation());
            expect(result.current.formatPatientName('  DANIEL opazo  ')).toBe('Daniel Opazo');
        });

        it('should return original value if empty', () => {
            const { result } = renderHook(() => usePatientValidation());
            expect(result.current.formatPatientName('')).toBe('');
            expect(result.current.formatPatientName('   ')).toBe('   ');
        });
    });

    describe('validateRut', () => {
        it('should format a valid raw RUT', () => {
            const { result } = renderHook(() => usePatientValidation());
            const validation = result.current.validateRut('14636523K');
            expect(validation.valid).toBe(true);
            expect(validation.value).toBe('14.636.523-K');
        });

        it('should detect and preserve passport format', () => {
            const { result } = renderHook(() => usePatientValidation());
            const validation = result.current.validateRut('P123456');
            expect(validation.valid).toBe(true);
            expect(validation.value).toBe('P123456');
        });

        it('should return trimmed invalid RUT as-is but valid', () => {
            const { result } = renderHook(() => usePatientValidation());
            const validation = result.current.validateRut('  abcd  ');
            expect(validation.valid).toBe(true);
            expect(validation.value).toBe('abcd');
        });
    });

    describe('validateAdmissionDate', () => {
        it('should reject a future date', () => {
            const { result } = renderHook(() => usePatientValidation());
            const futureDate = new Date();
            futureDate.setDate(futureDate.getDate() + 1);
            const dateStr = futureDate.toISOString().split('T')[0];

            const validation = result.current.validateAdmissionDate(dateStr);
            expect(validation.valid).toBe(false);
            expect(validation.error).toBe('La fecha de ingreso no puede ser futura');
        });

        it('should accept today or a past date', () => {
            const { result } = renderHook(() => usePatientValidation());
            // Use local date YYYY-MM-DD instead of UTC toISOString()
            const now = new Date();
            const year = now.getFullYear();
            const month = String(now.getMonth() + 1).padStart(2, '0');
            const day = String(now.getDate()).padStart(2, '0');
            const todayStr = `${year}-${month}-${day}`;

            const validation = result.current.validateAdmissionDate(todayStr);
            expect(validation.valid).toBe(true);

            const pastValidation = result.current.validateAdmissionDate('2000-01-01');
            expect(pastValidation.valid).toBe(true);
        });
    });

    describe('processFieldValue', () => {
        it('should route patientName to formatPatientName', () => {
            const { result } = renderHook(() => usePatientValidation());
            const res = result.current.processFieldValue('patientName', 'juan perez');
            expect(res.value).toBe('Juan Perez');
        });

        it('should route rut to validateRut', () => {
            const { result } = renderHook(() => usePatientValidation());
            const res = result.current.processFieldValue('rut', '14636523k');
            expect(res.value).toBe('14.636.523-K');
        });

        it('should route admissionDate to validateAdmissionDate', () => {
            const { result } = renderHook(() => usePatientValidation());
            const res = result.current.processFieldValue('admissionDate', '2000-01-01');
            expect(res.valid).toBe(true);
        });

        it('should return other fields as-is', () => {
            const { result } = renderHook(() => usePatientValidation());
            const res = result.current.processFieldValue('age', '25');
            expect(res.valid).toBe(true);
            expect(res.value).toBe('25');
        });
    });
});

