});

const createPatient = (name: string, bedId: string): PatientData => ({
    bedId,
    patientName: name,
    rut: '12345678-9',
    pathology: 'Diagnóstico Test',
    specialty: Specialty.MEDICINA,
    age: '45',
    insurance: 'Fonasa',
    origin: 'Residente',
    isRapanui: true,
    bedMode: 'Cama',
    hasCompanionCrib: false,
    isBlocked: false,
