            );

            await act(async () => {
                await result.current.sendMedicalHandoff('Template', 'group-id');
            });

            expect(whatsappService.sendWhatsAppMessage).toHaveBeenCalledWith(
                'group-id',
                expect.stringContaining('Dr. Previous')
            );
        });
    });
});

