        activeExtraBeds: [],
        lastUpdated: new Date().toISOString(),
    });

    const createDenseRecord = (date: string): DailyRecord => ({
        date,
        beds: {
            'BED_01': {
                bedId: 'BED_01',
                patientName: 'John Doe',
                handoffNote: 'Stable patient',
                isBlocked: false,
                bedMode: 'Cama',
                hasCompanionCrib: false,
                rut: '123-4',
                age: '40',
                status: 'Estable',
                admissionDate: '2024-01-01',
                admissionTime: '10:00',
                hasWristband: true,
                devices: []
            } as any,
            'BED_02': {
                bedId: 'BED_02',
                patientName: 'Jane Smith',
                isBlocked: false,
                bedMode: 'Cama',
                hasCompanionCrib: false,
                rut: '567-8',
                age: '30',
                status: 'Grave',
                admissionDate: '2024-01-01',
                admissionTime: '11:00',
                hasWristband: true,
                devices: []
            } as any
        },
        discharges: [],
        transfers: [],
        cma: [],
        lastUpdated: new Date().toISOString(),
        novedadesDayShift: 'Some news'
    } as any);

    describe('calculateDensity', () => {
        it('should return 0 for null/undefined', () => {
            expect(calculateDensity(null)).toBe(0);
        });

        it('should return low score for empty record', () => {
            const empty = createEmptyRecord('2024-01-01');
            expect(calculateDensity(empty)).toBe(0);
        });

        it('should return high score for dense record', () => {
            const dense = createDenseRecord('2024-01-01');
            const density = calculateDensity(dense);
            expect(density).toBeGreaterThan(20);
        });
    });

    describe('checkRegression', () => {
        it('should NOT flag regression when oldRecord is null', () => {
            const newRecord = createDenseRecord('2024-01-01');
            const result = checkRegression(null, newRecord);
            expect(result.isSuspicious).toBe(false);
        });

        it('should flag regression when dense record is overwritten by empty one', () => {
            const oldRecord = createDenseRecord('2024-01-01');
            const newRecord = createEmptyRecord('2024-01-01');

            const result = checkRegression(oldRecord, newRecord);
            expect(result.isSuspicious).toBe(true);
            expect(result.dropPercentage).toBe(100);
        });

        it('should NOT flag regression when drop is minimal', () => {
            const oldRecord = createDenseRecord('2024-01-01');
            const newRecord = { ...oldRecord, beds: { ...oldRecord.beds } };
            // Remove one minor field
            delete (newRecord.beds['BED_01'] as any).handoffNote;

            const result = checkRegression(oldRecord, newRecord);
            expect(result.isSuspicious).toBe(false);
        });

        it('should flag regression when losing a substantial number of patients', () => {
            // Create a very dense record with 10 patients
            const oldRecord = createEmptyRecord('2024-01-01');
            for (let i = 0; i < 10; i++) {
                oldRecord.beds[`BED_${i}`] = { patientName: `Patient ${i}` } as any;
            }

            // New record only has 2 patients
            const newRecord = createEmptyRecord('2024-01-01');
            newRecord.beds['BED_0'] = { patientName: 'Patient 0' } as any;
            newRecord.beds['BED_1'] = { patientName: 'Patient 1' } as any;

            const result = checkRegression(oldRecord, newRecord);
            expect(result.isSuspicious).toBe(true);
            expect(result.dropPercentage).toBe(80);
        });
    });
});

import { describe, it, expect } from 'vitest';
import { applyPatches } from '@/utils/patchUtils';

describe('patchUtils', () => {
    it('should update a simple top-level property', () => {
        const obj = { name: 'Old', age: 30 };
        const patches = { name: 'New' };
        const result = applyPatches(obj, patches);
        expect(result.name).toBe('New');
        expect(result.age).toBe(30);
    });

    it('should update a nested property using dot notation', () => {
        const obj = { beds: { R1: { name: 'Old' } } };
        const patches = { 'beds.R1.name': 'New' };
        const result = applyPatches(obj, patches);
        expect(result.beds.R1.name).toBe('New');
    });

    it('should auto-vivify missing paths', () => {
        const obj = {};
        const patches = { 'a.b.c': 123 };
        const result: any = applyPatches(obj, patches);
        expect(result.a.b.c).toBe(123);
    });

    it('should preserve other sibling properties during nested update', () => {
        const obj = {
            beds: {
                R1: { name: 'Juan', age: 40 },
                R2: { name: 'Maria' }
            }
        };
        const patches = { 'beds.R1.age': 41 };
        const result = applyPatches(obj, patches);
        expect(result.beds.R1.name).toBe('Juan');
        expect(result.beds.R1.age).toBe(41);
        expect(result.beds.R2.name).toBe('Maria');
    });

    it('should handle array values correctly', () => {
        const obj = { tags: ['old'] };
        const patches = { tags: ['new', 'extra'] };
        const result = applyPatches(obj, patches);
        expect(result.tags).toEqual(['new', 'extra']);
    });
});

/**
 * Tests for Admission Dates Validation
 * Verifies that admission dates are validated correctly.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';

// Test date validation logic
describe('Admission Date Validation', () => {
    const today = new Date();
    const todayStr = today.toISOString().split('T')[0];

    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    const yesterdayStr = yesterday.toISOString().split('T')[0];

    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);
    const tomorrowStr = tomorrow.toISOString().split('T')[0];

    describe('Date Format Validation', () => {
        it('should accept valid YYYY-MM-DD format', () => {
            const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
            expect(dateRegex.test('2024-12-23')).toBe(true);
            expect(dateRegex.test('2024-01-01')).toBe(true);
        });

        it('should reject invalid date formats', () => {
            const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
            expect(dateRegex.test('23-12-2024')).toBe(false);
            expect(dateRegex.test('2024/12/23')).toBe(false);
            expect(dateRegex.test('December 23, 2024')).toBe(false);
        });
    });

    describe('Future Date Prevention', () => {
        const isFutureDate = (dateStr: string, currentDateStr: string): boolean => {
            return dateStr > currentDateStr;
        };

        it('should identify future dates correctly', () => {
            expect(isFutureDate(tomorrowStr, todayStr)).toBe(true);
        });

        it('should allow today date', () => {
            expect(isFutureDate(todayStr, todayStr)).toBe(false);
        });

        it('should allow past dates', () => {
            expect(isFutureDate(yesterdayStr, todayStr)).toBe(false);
        });
    });

    describe('Date Parsing', () => {
        it('should parse valid dates correctly', () => {
            const dateStr = '2024-12-23';
            const [year, month, day] = dateStr.split('-').map(Number);
            expect(year).toBe(2024);
            expect(month).toBe(12);
            expect(day).toBe(23);
        });

        it('should handle edge cases like year boundaries', () => {
            const dec31 = '2024-12-31';
            const jan1 = '2025-01-01';
            expect(jan1 > dec31).toBe(true);
        });
    });
});

import { describe, it, expect } from 'vitest';
import {
    DailyRecordSchema,
    safeParseDailyRecord,
    parseDailyRecordWithDefaults
} from '@/schemas/zodSchemas';

describe('Data Schema Resilience (Fuzzing)', () => {
    it('should fail gracefully on totally corrupted data', () => {
        const corrupted = {
            date: 12345, // Should be string
            beds: "not-an-object",
            discharges: null
        };

        const result = safeParseDailyRecord(corrupted);
        expect(result).toBeNull();
    });

    it('should recover basic structure using parseDailyRecordWithDefaults', () => {
        const partiallyCorrupted = {
            date: '2024-12-25',
            beds: 'INVALID_DATA',
            nurses: 'NOT_AN_ARRAY'
        };

        const result = parseDailyRecordWithDefaults(partiallyCorrupted, '2024-12-25');

        expect(result.date).toBe('2024-12-25');
        expect(result.beds).toEqual({}); // Recovered default
        expect(Array.isArray(result.nurses)).toBe(true); // Recovered default
    });

    it('should handle unexpected enum values in PatientData', () => {
        const invalidPatient = {
            date: '2024-12-25',
            beds: {
                'BED_01': {
                    patientName: 'CORRUPT TEST',
                    status: 'SUPER_GRAVE', // Invalid enum
                    biologicalSex: 'ROBOT' // Invalid enum
                }
            }
        };

        const result = safeParseDailyRecord(invalidPatient);
        // Currently safeParse returns null if ANY part fails
        expect(result).toBeNull();
    });

    it('should passthrough extra fields (forward compatibility)', () => {
        const dataWithFutureFields = {
            date: '2024-12-25',
            beds: {},
            newFeatureFlag: true,
            v4Metadata: { region: 'hospital' }
        };

        const result = safeParseDailyRecord(dataWithFutureFields);
        expect(result).not.toBeNull();
        expect((result as any).newFeatureFlag).toBe(true);
    });
});

