describe('MovementsSummary', () => {
    it('renders empty messages for day shift', () => {
        const record = createMockRecord('2024-12-11');
        render(<MovementsSummary record={record} selectedShift="day" />);

        expect(screen.getByText(/No hay altas registradas en este turno/i)).toBeInTheDocument();
        expect(screen.getByText(/No hay traslados registrados en este turno/i)).toBeInTheDocument();
        expect(screen.getByText(/No hay pacientes de CMA hoy/i)).toBeInTheDocument();
    });

    it('renders empty messages for night shift', () => {
        const record = createMockRecord('2024-12-11');
        render(<MovementsSummary record={record} selectedShift="night" />);

        expect(screen.getByText(/No hay altas registradas durante la noche/i)).toBeInTheDocument();
        expect(screen.getByText(/No hay traslados registrados durante la noche/i)).toBeInTheDocument();
        expect(screen.getByText(/CMA solo aplica para turno de día/i)).toBeInTheDocument();
    });

    it('filters discharges and transfers by shift time', () => {
        const record = createMockRecord('2024-12-11');

        // 10:00 is Day Shift (08:00-20:00)
        // 22:00 is Night Shift (20:00-08:00)

        record.discharges = [
            { id: 'd1', bedId: 'B1', bedName: 'B1', bedType: 'Adulto', patientName: 'Day Discharge', rut: '1', time: '10:00', diagnosis: 'D1', dischargeType: 'Domicilio (Habitual)', status: 'Vivo' },
            { id: 'd2', bedId: 'B2', bedName: 'B2', bedType: 'Adulto', patientName: 'Night Discharge', rut: '2', time: '22:00', diagnosis: 'D2', dischargeType: 'Domicilio (Habitual)', status: 'Vivo' },
            { id: 'd3', bedId: 'B3', bedName: 'B3', bedType: 'Adulto', patientName: 'No Time Discharge', rut: '3', time: '', diagnosis: 'D3', dischargeType: 'Domicilio (Habitual)', status: 'Vivo' },
        ];

        record.transfers = [
            { id: 't1', bedId: 'T1', bedName: 'T1', bedType: 'Adulto', patientName: 'Day Transfer', rut: '4', time: '14:00', diagnosis: 'D4', evacuationMethod: 'Ambulancia', receivingCenter: 'H1' },
            { id: 't2', bedId: 'T2', bedName: 'T2', bedType: 'Adulto', patientName: 'Night Transfer', rut: '5', time: '02:00', diagnosis: 'D5', evacuationMethod: 'Ambulancia', receivingCenter: 'H2' },
        ];

        const { rerender } = render(<MovementsSummary record={record} selectedShift="day" />);

        expect(screen.getByText('Day Discharge')).toBeInTheDocument();
        expect(screen.getByText('No Time Discharge')).toBeInTheDocument();
        expect(screen.queryByText('Night Discharge')).not.toBeInTheDocument();

        expect(screen.getByText('Day Transfer')).toBeInTheDocument();
        expect(screen.queryByText('Night Transfer')).not.toBeInTheDocument();

        // Switch to Night
        rerender(<MovementsSummary record={record} selectedShift="night" />);

        expect(screen.getByText('Night Discharge')).toBeInTheDocument();
        expect(screen.queryByText('Day Discharge')).not.toBeInTheDocument();
        expect(screen.queryByText('No Time Discharge')).not.toBeInTheDocument();

        expect(screen.getByText('Night Transfer')).toBeInTheDocument();
        expect(screen.queryByText('Day Transfer')).not.toBeInTheDocument();
    });

    it('renders CMA patients only on day shift', () => {
        const record = createMockRecord('2024-12-11');
        record.cma = [
            { id: 'c1', bedName: 'C1', patientName: 'CMA Patient', rut: '6', age: '40', diagnosis: 'D6', specialty: 'Medicina', interventionType: 'Cirugía Mayor Ambulatoria' }
        ];

        const { rerender } = render(<MovementsSummary record={record} selectedShift="day" />);
        expect(screen.getByText('CMA Patient')).toBeInTheDocument();

        rerender(<MovementsSummary record={record} selectedShift="night" />);
        expect(screen.queryByText('CMA Patient')).not.toBeInTheDocument();
        expect(screen.getByText(/CMA solo aplica para turno de día/i)).toBeInTheDocument();
    });

    it('handles special values like receivingCenterOther', () => {
        const record = createMockRecord('2024-12-11');
        record.transfers = [
            {
                id: 't1',
                bedId: 'T1',
                bedName: 'T1',
                bedType: 'Adulto',
                patientName: 'Other Transfer',
                rut: '7',
                time: '12:00',
                diagnosis: 'D4',
                evacuationMethod: 'Ambulancia',
                receivingCenter: 'Otro',
                receivingCenterOther: 'Especial Hospital'
            },
        ];

        render(<MovementsSummary record={record} selectedShift="day" />);
        expect(screen.getByText('Especial Hospital')).toBeInTheDocument();
        expect(screen.queryByText('Otro')).not.toBeInTheDocument();
    });
});

/**
 * Backup Files Types
 * Types for the cloud backup files system
 */

/**
 * Types of files that can be backed up
 */
export type BackupFileType = 'NURSING_HANDOFF' | 'MEDICAL_HANDOFF' | 'CENSUS';

/**
 * Shift types for handoff backups
 */
export type BackupShiftType = 'day' | 'night';

/**
 * Backup statistics
 */
export interface BackupStats {
    totalRecords: number;
}

/**
 * User information for audit trail
 */
export interface BackupCreator {
    uid: string;
    email: string;
    name: string;
}

/**
 * Metadata for handoff backups
 */
export interface HandoffBackupMetadata {
    deliveryStaff: string;
    receivingStaff: string;
    patientCount: number;
    shiftType: BackupShiftType;
}

/**
 * Generic metadata (extensible for other backup types)
 */
export interface BackupFileMetadata extends Partial<HandoffBackupMetadata> {
    [key: string]: unknown;
}

/**
 * Full backup file with content (for viewing/restoring)
 */
export interface BackupFile {
    id: string;
    type: BackupFileType;
    shiftType?: BackupShiftType;
    date: string;                    // YYYY-MM-DD format
    title: string;                   // Display title
    createdAt: string;               // ISO timestamp
    createdBy: BackupCreator;
    metadata: BackupFileMetadata;
    content: Record<string, unknown>; // Snapshot of the data
}

/**
 * Backup file preview (for listing without loading full content)
 */
export interface BackupFilePreview extends Omit<BackupFile, 'content'> {
    // Used for list views to avoid loading large content
}

/**
 * Data needed to create a new backup
 */
export interface CreateBackupData {
    type: BackupFileType;
    shiftType?: BackupShiftType;
    date: string;
    title: string;
    metadata: BackupFileMetadata;
    content: Record<string, unknown>;
}

/**
 * Filter options for listing backups
 */
export interface BackupFilters {
    type?: BackupFileType;
    shiftType?: BackupShiftType;
    dateFrom?: string;
    dateTo?: string;
    searchQuery?: string;
}

/**
 * Configuration for backup file types
 */
export const BACKUP_TYPE_CONFIG: Record<BackupFileType, {
    label: string;
    icon: string;
    color: string;
}> = {
    NURSING_HANDOFF: {
        label: 'Entrega Enfermería',
        icon: '🏥',
        color: 'teal'
    },
    MEDICAL_HANDOFF: {
        label: 'Entrega Médicos',
        icon: '🩺',
        color: 'blue'
    },
    CENSUS: {
        label: 'Censo Diario',
        icon: '📋',
        color: 'purple'
    }
};

/**
 * Configuration for shift types
 */
export const SHIFT_TYPE_CONFIG: Record<BackupShiftType, {
    label: string;
    shortLabel: string;
}> = {
    day: {
        label: 'Turno Largo',
        shortLabel: 'Día'
    },
    night: {
        label: 'Turno Noche',
        shortLabel: 'Noche'
    }
};

/**
 * WhatsApp Integration Types
 * 
 * Types for shift parsing and handoff delivery via WhatsApp
 */

// ============================================
// SHIFT MANAGEMENT
// ============================================

/**
 * Weekly shift schedule for operating room staff
 */
export interface WeeklyShift {
    /** Start date in YYYY-MM-DD format */
    startDate: string;
    /** End date in YYYY-MM-DD format */
    endDate: string;
    /** Where this shift data came from */
    source: 'whatsapp' | 'manual';
    /** When this was parsed/created */
    parsedAt: string;
    /** List of staff members on duty */
    staff: ShiftStaffMember[];
    /** Original WhatsApp message (for reference) */
    originalMessage?: string;
}

/**
 * Individual staff member on shift
 */
export interface ShiftStaffMember {
    /** Role/position (e.g., "Cirujana", "Anestesista") */
    role: string;
    /** Full name */
    name: string;
    /** Phone number in format +56 9 XXXX XXXX */
    phone: string;
    /** WhatsApp deep link */
    whatsappUrl: string;
    /** Notes about this staff member */
    notes?: string;
    /** Replacement info if they change mid-week */
    replacement?: {
        name: string;
        phone: string;
        whatsappUrl: string;
        /** When replacement starts (ISO date string) */
        startDate: string;
    };
}

// ============================================
// HANDOFF DELIVERY
// ============================================

/**
 * WhatsApp delivery status for a medical handoff
 */
export interface HandoffWhatsAppStatus {
    /** Whether the handoff has been sent to WhatsApp */
    sent: boolean;
    /** When it was sent (ISO date string) */
    sentAt: string | null;
    /** How it was sent */
    method: 'MANUAL' | 'AUTO' | 'NOT_SENT';
    /** Who triggered manual send (if applicable) */
    sentBy?: string;
    /** Target WhatsApp group ID */
    targetGroupId?: string;
    /** WhatsApp message ID (for tracking) */
    messageId?: string;
}

/**
 * Auto-send configuration for a handoff
 */
export interface HandoffAutoSend {
    /** Whether auto-send is enabled */
    enabled: boolean;
    /** Time to auto-send (HH:MM format, e.g. "17:00") */
    scheduledTime: string;
    /** Whether auto-send has been executed */
    executed: boolean;
    /** When it was executed (if auto-sent) */
    executedAt?: string;
}

// ============================================
// WHATSAPP CONFIGURATION
// ============================================

/**
 * WhatsApp integration configuration
 */
export interface WhatsAppConfig {
    /** Whether WhatsApp integration is enabled */
    enabled: boolean;
    /** Connection status */
    status: 'disconnected' | 'connecting' | 'connected' | 'error';
    /** Last connection time */
    lastConnected?: string;
    /** Shift parser configuration */
    shiftParser: {
        enabled: boolean;
        /** WhatsApp group ID to monitor for shifts */
        sourceGroupId: string;
    };
    /** Handoff notification configuration */
    handoffNotifications: {
        enabled: boolean;
        /** WhatsApp group ID to send notifications to */
        targetGroupId: string;
        /** Auto-send time (HH:MM) */
        autoSendTime: string;
    };
}

// ============================================
// LOGS
// ============================================

/**
 * Log entry for WhatsApp operations
 */
export interface WhatsAppLog {
    id: string;
    timestamp: string;
    type: 'HANDOFF_SENT' | 'SHIFT_PARSED' | 'MESSAGE_RECEIVED' | 'ERROR';
    method?: 'MANUAL' | 'AUTO';
    userId?: string;
    groupId?: string;
    messageId?: string;
    success: boolean;
    error?: string;
    metadata?: Record<string, any>;
}

